lex;\n  border-radius: 0.5rem;\n  overflow: hidden;\n}\n.formulario__icono {\n  background-color: #676d7a;\n  width: 4rem;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n.formulario__icono i {\n  color: #FFFFFF;\n  font-size: 2rem;\n}\n.formulario__label {\n  display: block;\n  font-size: 1.4rem;\n  font-weight: 500;\n  color: rgba(26, 27, 21, 0.85);\n}\n.formulario__input, .formulario__input--sociales, .formulario__select--sociales, .formulario__select {\n  outline: none;\n  font-size: 1.2rem;\n  padding: 0.5rem;\n  border: 1px solid #aeaeae;\n  border-radius: 0.5rem;\n}\n.formulario__input--file, .formulario__select--file {\n  border: none;\n}\n.formulario__input--sociales, .formulario__select--sociales {\n  flex: 1;\n  border-top-left-radius: 0;\n  border-bottom-left-radius: 0;\n}\n.formulario__contentinputfile {\n  margin: 0 auto;\n  height: 15rem;\n  width: 15rem;\n  border: 2px dashed #e1e1e1;\n  position: relative;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n.formulario__contentinputfile--sm {\n  height: 9rem;\n  width: 10rem;\n}\n.formulario__imginputfile {\n  width: 100%;\n  height: 100%;\n  position: absolute;\n}\n.formulario__imginputfile img {\n  width: 100%;\n  height: 100%;\n  object-fit: cover;\n}\n.formulario__textarea {\n  font-size: 1.2rem;\n  padding: 1rem;\n  border: 1px solid #aeaeae;\n  border-radius: 0.5rem;\n  outline-color: #78808a;\n}\n.formulario__dato {\n  display: flex;\n}\n.formulario__dato input {\n  flex: 1;\n  border-top-right-radius: 0;\n  border-bottom-right-radius: 0;\n}\n.formulario__dato label {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  border-radius: 0.5rem;\n  border: 1px solid #aeaeae;\n  width: 4rem;\n  border-top-left-radius: 0;\n  border-bottom-left-radius: 0;\n  border-left: none;\n}\n.formulario__radio {\n  display: flex;\n  gap: 2rem;\n}\n.formulario__texto {\n  margin-top: 3rem;\n}\n.formulario__imagen {\n  max-width: 20rem;\n}\n.formulario__submit {\n  background-color: #3d72fc;\n  padding: 1rem 2rem;\n  color: #FFFFFF;\n  font-size: 1.4rem;\n  font-weight: 700;\n  border: none;\n  transition-property: background-color;\n  transition-duration: 0.3s;\n  text-align: center;\n  width: 100%;\n  display: inline-block;\n  border-radius: 0.5rem;\n  align-self: flex-start;\n  width: auto;\n  border-radius: 0.4rem;\n}\n.formulario__submit:hover {\n  background-color: #0b4dfb;\n  cursor: pointer;\n}\n.formulario__submit--eliminar {\n  background-color: #ff0000;\n  padding: 1rem 2rem;\n  color: #FFFFFF;\n  font-size: 1.4rem;\n  font-weight: 700;\n  border: none;\n  transition-property: background-color;\n  transition-duration: 0.3s;\n  text-align: center;\n  width: 100%;\n  display: inline-block;\n  border-radius: 0.5rem;\n  width: auto;\n  align-self: flex-start;\n}\n.formulario__submit--eliminar:hover {\n  background-color: #cc0000;\n  cursor: pointer;\n}\n.formulario__submit--login {\n  background-color: rgba(61, 114, 252, 0.9);\n  padding: 1rem 2rem;\n  color: #FFFFFF;\n  font-size: 1.4rem;\n  font-weight: 700;\n  border: none;\n  transition-property: background-color;\n  transition-duration: 0.3s;\n  text-align: center;\n  width: 100%;\n  display: inline-block;\n  border-radius: 0.5rem;\n  width: auto;\n  border-radius: 0.4rem;\n  align-self: center;\n}\n.formulario__submit--login:hover {\n  background-color: rgba(11, 77, 251, 0.9);\n  cursor: pointer;\n}\n\n.bloqueformulario__submit--login {\n  background-color: #3d72fc;\n  width: 100%;\n  border-radius: 0.4rem;\n}\n.bloqueformulario__submit--login:hover {\n  background-color: #3c3f42;\n}\n\n.acciones, .acciones__Centrar {\n  margin: 2rem 1rem 1rem 1rem;\n  display: flex;\n  justify-content: space-between;\n}\n.acciones__Centrar {\n  justify-content: center;\n}\n.acciones__enlace {\n  color: #3c3f42;\n  font-size: 1.4rem;\n  font-weight: 300;\n}\n\n.wrapper {\n  display: flex;\n}\n\n.acordeon {\n  max-height: 0rem;\n  overflow: hidden;\n  transiti