 */\n/**\n * Remove the gray background on active links in IE 10.\n */\na {\n  background-color: transparent;\n}\n\n/**\n * 1. Remove the bottom border in Chrome 57-\n * 2. Add the correct text decoration in Chrome, Edge, IE, Opera, and Safari.\n */\nabbr[title] {\n  border-bottom: none; /* 1 */\n  text-decoration: underline; /* 2 */\n  text-decoration: underline dotted; /* 2 */\n}\n\n/**\n * Add the correct font weight in Chrome, Edge, and Safari.\n */\nb,\nstrong {\n  font-weight: bolder;\n}\n\n/**\n * 1. Correct the inheritance and scaling of font size in all browsers.\n * 2. Correct the odd `em` font sizing in all browsers.\n */\ncode,\nkbd,\nsamp {\n  font-family: monospace, monospace; /* 1 */\n  font-size: 1em; /* 2 */\n}\n\n/**\n * Add the correct font size in all browsers.\n */\nsmall {\n  font-size: 80%;\n}\n\n/**\n * Prevent `sub` and `sup` elements from affecting the line height in\n * all browsers.\n */\nsub,\nsup {\n  font-size: 75%;\n  line-height: 0;\n  position: relative;\n  vertical-align: baseline;\n}\n\nsub {\n  bottom: -0.25em;\n}\n\nsup {\n  top: -0.5em;\n}\n\n/* Embedded content\n   ========================================================================== */\n/**\n * Remove the border on images inside links in IE 10.\n */\nimg {\n  border-style: none;\n}\n\n/* Forms\n   ========================================================================== */\n/**\n * 1. Change the font styles in all browsers.\n * 2. Remove the margin in Firefox and Safari.\n */\nbutton,\ninput,\noptgroup,\nselect,\ntextarea {\n  font-family: inherit; /* 1 */\n  font-size: 100%; /* 1 */\n  line-height: 1.15; /* 1 */\n  margin: 0; /* 2 */\n}\n\n/**\n * Show the overflow in IE.\n * 1. Show the overflow in Edge.\n */\nbutton,\ninput { /* 1 */\n  overflow: visible;\n}\n\n/**\n * Remove the inheritance of text transform in Edge, Firefox, and IE.\n * 1. Remove the inheritance of text transform in Firefox.\n */\nbutton,\nselect { /* 1 */\n  text-transform: none;\n}\n\n/**\n * Correct the inability to style clickable types in iOS and Safari.\n */\nbutton,\n[type=button],\n[type=reset],\n[type=submit] {\n  -webkit-appearance: button;\n}\n\n/**\n * Remove the inner border and padding in Firefox.\n */\nbutton::-moz-focus-inner,\n[type=button]::-moz-focus-inner,\n[type=reset]::-moz-focus-inner,\n[type=submit]::-moz-focus-inner {\n  border-style: none;\n  padding: 0;\n}\n\n/**\n * Restore the focus styles unset by the previous rule.\n */\nbutton:-moz-focusring,\n[type=button]:-moz-focusring,\n[type=reset]:-moz-focusring,\n[type=submit]:-moz-focusring {\n  outline: 1px dotted ButtonText;\n}\n\n/**\n * Correct the padding in Firefox.\n */\nfieldset {\n  padding: 0.35em 0.75em 0.625em;\n}\n\n/**\n * 1. Correct the text wrapping in Edge and IE.\n * 2. Correct the color inheritance from `fieldset` elements in IE.\n * 3. Remove the padding so developers are not caught out when they zero out\n *    `fieldset` elements in all browsers.\n */\nlegend {\n  box-sizing: border-box; /* 1 */\n  color: inherit; /* 2 */\n  display: table; /* 1 */\n  max-width: 100%; /* 1 */\n  padding: 0; /* 3 */\n  white-space: normal; /* 1 */\n}\n\n/**\n * Add the correct vertical alignment in Chrome, Firefox, and Opera.\n */\nprogress {\n  vertical-align: baseline;\n}\n\n/**\n * Remove the default vertical scrollbar in IE 10+.\n */\ntextarea {\n  overflow: auto;\n}\n\n/**\n * 1. Add the correct box sizing in IE 10.\n * 2. Remove the padding in IE 10.\n */\n[type=checkbox],\n[type=radio] {\n  box-sizing: border-box; /* 1 */\n  padding: 0; /* 2 */\n}\n\n/**\n * Correct the cursor style of increment and decrement buttons in Chrome.\n */\n[type=number]::-webkit-inner-spin-button,\n[type=number]::-webkit-outer-spin-button {\n  height: auto;\n}\n\n/**\n * 1. Correct the odd appearance in Chrome and Safari.\n * 2. Correct the outline style in Safari.\n */\n[type=search] {\n  -webkit-appearance: textfield; /* 1 */\n  outline-offset: -2px; /* 2 */\n}\n\n/**\n * Remove the inner padding in Chrome and Safari on macOS.\n */\n[type=search]::-webkit-search-decoration {\n  -webkit-appearance: none;\n}\n\n/**\n * 1. Correct the inability to style clickable types in iOS and Safari.\n * 2. Change font properties to `inherit` in Safari.\n */\n::-webkit-file-upload-button {\n  -webkit-appearance: button; /* 1 */\n  font: inherit; /* 2 */\n}\n\n/* Interactive\n   ========================================================================== */\n/*\n * Add the correct display in Edge, IE 10+, and Firefox.\n */\ndetails {\n  display: block;\n}\n\n/*\n * Add the correct display in all browsers.\n */\nsummary {\n  display: list-item;\n}\n\n/* Misc\n   ========================================================================== */\n/**\n * Add the correct display in IE 10+.\n */\ntemplate {\n  display: none;\n}\n\n/**\n * Add the correct display in IE 10.\n */\n[hidden] {\n  display: none;\n}\n\nhtml {\n  font-size: 62.5%;\n  box-sizing: border-box;\n  height: 100%;\n}\n\n*, *:before, *:after {\n  box-sizing: inherit;\n}\n\nbody {\n  font-family: \"Poppins\", sans-serif;\n  font-size: 1.4rem;\n}\n\na {\n  text-decoration: none;\n}\n\nul {\n  padding: 0;\n  list-style: none;\n  margin: 0;\n}\n\nli {\n  list-style: none;\n}\n\nimg {\n  width: 100%;\n  height: auto;\n}\n\n.contenedor {\n  width: 95%;\n  max-width: 1200px;\n  margin: 0 auto;\n}\n\n.contenedor-sm {\n  width: 95%;\n  max-width: 60rem;\n  margin: 0 auto;\n}\n\n.box {\n  padding: 1rem;\n  background-color: #FFFFFF;\n}\n\ninput[type=number]:focus {\n  outline: none !important;\n}\n\nh1 {\n  font-size: 4.2rem;\n  margin: 0;\n}\n\nh2 {\n  font-size: 3.4rem;\n  margin: 0;\n}\n\nh3 {\n  font-size: 2.6rem;\n  margin: 0;\n}\n\nh4 {\n  font-size: 2rem;\n  margin: 0;\n}\n\nh5 {\n  font-size: 1.7rem;\n  margin: 0;\n}\n\np {\n  margin: 1rem 0;\n}","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.formulario{\r\n    display: flex;\r\n    flex-direction: column;\r\n    /*\r\n    &__legend{\r\n        color: v.$gris;\r\n        font-size: 2.2rem;\r\n        margin-bottom: 2rem;\r\n    }*/\r\n    &__fieldset{\r\n        border: none;\r\n        padding: 0;\r\n    }\r\n    &__campo{\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: .6rem;\r\n        margin: 0 0 1.5rem 0;\r\n    }\r\n    &__contenedor-icono{\r\n        display: flex;\r\n        border-radius: .5rem;\r\n        overflow: hidden;\r\n    }\r\n    &__icono{\r\n        background-color: v.$gris60;\r\n        width: 4rem;\r\n        display: flex;\r\n        justify-content: center;\r\n        align-items: center;\r\n        i{\r\n           color: v.$blanco;\r\n           font-size: 2rem;\r\n        }\r\n    }\r\n    &__label{\r\n        display: block;\r\n        font-size: 1.4rem;\r\n        font-weight: 500;\r\n        color: rgba(v.$negro90, 0.85);\r\n    }\r\n    &__input, &__select{\r\n        outline: none;\r\n        font-size: 1.2rem;\r\n        padding: .5rem;\r\n        border: 1px solid darken(v.$gris20, 20);\r\n        border-radius: .5rem;\r\n        &--file{\r\n            border: none;\r\n        }\r\n        &--sociales{\r\n            @extend .formulario__input;\r\n            flex: 1;\r\n            border-top-left-radius: 0;\r\n            border-bottom-left-radius: 0;\r\n        }\r\n    }\r\n    &__contentinputfile{\r\n        margin: 0 auto;\r\n        height: 15rem;\r\n        width: 15rem;\r\n        border: 2px dashed v.$gris20;\r\n        position: relative;\r\n        display: flex;\r\n        justify-content: center;\r\n        align-items: center;\r\n        &--sm{\r\n            height: 9rem;\r\n            width: 10rem;\r\n        }\r\n    }\r\n    &__imginputfile{\r\n        width: 100%;\r\n        height: 100%;\r\n        position: absolute;\r\n        img{\r\n            width: 100%;\r\n            height: 100%;\r\n            object-fit: cover;\r\n            \r\n        }\r\n    }\r\n    &__textarea{\r\n        font-size: 1.2rem;\r\n        padding: 1rem;\r\n        border: 1px solid darken(v.$gris20, 20);\r\n        border-radius: .5rem;\r\n        outline-color: v.$gris50;\r\n    }\r\n    &__dato{\r\n        display: flex;\r\n        input{\r\n            flex: 1;\r\n            border-top-right-radius: 0;\r\n            border-bottom-right-radius: 0;\r\n        }\r\n        label{\r\n            display: flex;\r\n            align-items: center;\r\n            justify-content: center;\r\n            border-radius: .5rem;\r\n            border: 1px solid darken(v.$gris20, 20);\r\n            width: 4rem;\r\n            border-top-left-radius: 0;\r\n            border-bottom-left-radius: 0;\r\n            border-left: none;\r\n        }\r\n    }\r\n    &__radio{\r\n        display: flex;\r\n        gap: 2rem;\r\n    }\r\n    &__texto{\r\n        margin-top: 3rem\r\n    }\r\n    &__imagen{\r\n        max-width: 20rem\r\n    }\r\n    &__listado{\r\n       // @include m.tags;\r\n    }\r\n    &__submit{\r\n        @include m.boton(v.$azul50, v.$blanco);\r\n        align-self: flex-start;\r\n        width: auto;\r\n        border-radius: .4rem;\r\n        &--eliminar{  //aplicado en adinconfig/index.php para eliminar empleado\r\n            @include m.boton(v.$rojo60, v.$blanco);  \r\n            width: auto;\r\n            align-self: flex-start;\r\n        }\r\n        &--login{  //aplicado en login, olvide, registro y dash-cliente\r\n            @include m.boton(rgba(v.$azul50, .9), v.$blanco);\r\n            width: auto;\r\n            border-radius: .4rem;\r\n            align-self: center;    \r\n        }\r\n    }\r\n\r\n}\r\n\r\n.bloqueformulario {\r\n\r\n    &__submit {\r\n\r\n        &--login {\r\n            background-color: v.$azul50;\r\n            width: 100%;\r\n            border-radius: .4rem;\r\n            &:hover {\r\n                background-color: v.$gris80\r\n            }\r\n        }\r\n    }\r\n}","// Fuentes\r\n$fuente-principal: \"Poppins\",sans-serif;//'Outfit', sans-serif;\r\n$fuente-secundaria: 'Ubuntu', sans-serif;\r\n$fuente-adicional: 'Concert One', cursive;\r\n// Tamaño de Media Queries\r\n$telefonomini: 425px;\r\n$telefono: 480px;\r\n$telefonom: 525px;\r\n$telefonol: 570px;\r\n$telefonoxl: 633px;\r\n$tablet: 768px;\r\n$tabletl: 820px; \r\n$tabletm: 880px;\r\n$xl_tablet: 992px;\r\n$desktop: 1024px;\r\n$xl_desktop: 1200px;\r\n$xxl_desktop: 1550px;\r\n\r\n// Colores\r\n/*\r\n$barprogress: rgb(240, 101, 72);\r\n$rojo: #ff0000;\r\n$rosa: #d2095d;\r\n$verde1: #02db02;\r\n$verde2:#329f00;\r\n$verdeclaro: #d3f800;\r\n$azul: #007df4;\r\n$azul1: #0da6f3;\r\n$azul2: #3d72fc;\r\n$azul3: #3564db;\r\n$azul4: #0043ed;\r\n$azul10: #e3e9fc;\r\n$azulclaro: #eff2f7;\r\n$azuloscuro: #051453; \r\n$sidebar2: #064CDB;\r\n$sidebar3: #30419b; //utilizado en el sidebar\r\n$sidebar4: #244f96;\r\n$iconos: #7081b9; \r\n$secundario: #00c8c2;\r\n$blackdark: #000;\r\n$negro: #1a1b15;\r\n$blanco: #FFFFFF;\r\n$gris: #64748B;\r\n$grisclaro: #e1e1e1;\r\n$griswhite: #F3F3F3;\r\n$grisraton: #a5a5a5;\r\n$grisoscuro: #585858;\r\n$grisblack: #2a2d30;\r\n\r\n*/\r\n\r\n$backdrop: rgba(0, 0, 0, .40);\r\n\r\n//////////////////\r\n$cyan: #0891B2;\r\n$indigo: #4338CA;\r\n$morado: #7C3AED;\r\n\r\n$azul100: #051453;\r\n$azul90: #062b88;\r\n$azul80: #0739b9;\r\n$azul70: #0043ed;\r\n$azul60: #2563EB;\r\n$azul50: #3d72fc;\r\n$azul40: #007df4;\r\n$azul30: #0da6f3;\r\n$azul20: #a2d1ee;\r\n$azul10: #e3e9fc;\r\n$azul0: #eff2f7;\r\n\r\n$naranja100: rgb(240, 101, 72);\r\n$naranja90:#f5690b;\r\n$naranja80:#f57c0b;\r\n$naranja70:#f5900b;\r\n$naranja60:#F59E0B;\r\n$naranja50:#f1a82a;\r\n$naranja40:#f3b54b;\r\n$naranja30:#eebe6b;\r\n$naranja20:#f5d08f;\r\n$naranja10:#ffe3b3;\r\n\r\n$amarillo80:#fcd62c;\r\n$amarillo70:#ffeb38;\r\n$amarillo60:#ffef5d;\r\n$amarillo50:#fdf289;\r\n$amarillo40:#fbfd89;\r\n\r\n$rosa: #DB2777;\r\n\r\n\r\n$negro100: #000;\r\n$negro90: #1a1b15;\r\n$gris80: #3c3f42;\r\n$gris70: #464e58;\r\n$gris60: #676d7a;\r\n$gris50: #78808a;\r\n$gris40: #979ea7;\r\n$gris30: #c0c5ca;\r\n$gris20: #e1e1e1;\r\n$gris10: #F3F3F3;\r\n$blanco: #FFFFFF;\r\n\r\n$rojo100: #960707;\r\n$rojo90: rgb(169, 0, 0);\r\n$rojo80: #c40e0e;\r\n$rojo70: #d80101;\r\n$rojo60: #ff0000;\r\n$rojo50: #ff2b2b;\r\n$rojo40: #ff4848;\r\n$rojo30: #fd6459;\r\n$rojo20: #ff6f6a;\r\n$rojo10: #ff8b8b;\r\n\r\n$verde100: rgb(10, 78, 10);\r\n$verde90: rgb(8, 100, 8);\r\n$verde80: rgb(4, 124, 4);\r\n$verde70: rgb(9, 146, 9);\r\n$verde60:#02a710;\r\n$verde50:#22bd2f;\r\n$verde40:#48c953;\r\n$verde30:#6fd678;\r\n$verde20:#8ee095;\r\n$verde10:#c0ecc4;\r\n\r\n$lima: #02db02;\r\n$turquesa: #00c8c2;\r\n\r\n// Fuentes\r\n$delgada: 300;\r\n$regular: 400;\r\n$bold: 700;\r\n$black: 900;","@use 'variables' as v;\r\n\r\n/** Media Queries **/\r\n@mixin telefono {\r\n    @media (min-width: v.$telefono) {\r\n        @content;\r\n    }\r\n}\r\n@mixin telefonomini {\r\n    @media (min-width: v.$telefonomini) {\r\n        @content;\r\n    }\r\n}\r\n@mixin telefonom {\r\n    @media (min-width: v.$telefonom) {\r\n        @content;\r\n    }\r\n}\r\n@mixin telefonol {\r\n    @media (min-width: v.$telefonol) {\r\n        @content;\r\n    }\r\n}\r\n@mixin telefonoxl {\r\n    @media (min-width: v.$telefonoxl) {\r\n        @content;\r\n    }\r\n}\r\n@mixin tablet {\r\n    @media (min-width: v.$tablet) {\r\n        @content;\r\n    }\r\n}\r\n@mixin tabletl {\r\n    @media (min-width: v.$tabletl){\r\n        @content;\r\n    }\r\n}\r\n@mixin tabletm {\r\n    @media (min-width: v.$tabletm) {\r\n        @content;\r\n    }\r\n}\r\n@mixin xl_tablet {\r\n    @media (min-width: v.$xl_tablet) {\r\n        @content;\r\n    }\r\n}\r\n@mixin desktop {\r\n    @media (min-width: v.$desktop) {\r\n        @content;\r\n    }\r\n}\r\n@mixin xl_desktop {\r\n    @media (min-width: v.$xl_desktop) {\r\n        @content;\r\n    }\r\n}\r\n@mixin xxl_desktop {\r\n    @media (min-width: v.$xxl_desktop) {\r\n        @content;\r\n    }\r\n}\r\n\r\n\r\n@mixin boton($bgColor, $colorTexto) {\r\n    background-color: $bgColor;\r\n    padding: 1rem 2rem;\r\n    color: $colorTexto;\r\n    font-size: 1.4rem;\r\n    font-weight: 700;\r\n    border: none;\r\n    transition-property: background-color;\r\n    transition-duration: .3s;\r\n    text-align: center;\r\n    width: 100%;\r\n    display: inline-block;\r\n    border-radius: .5rem;\r\n    &:hover {\r\n        background-color: darken( $bgColor, 10% );\r\n        cursor: pointer;\r\n    }\r\n}\r\n\r\n@mixin grid($columnas, $espaciado ) {\r\n    display: grid;\r\n    gap: $espaciado;\r\n    grid-template-columns: repeat($columnas, 1fr);\r\n}\r\n\r\n@mixin contenedor{\r\n    //max-width: 120rem;\r\n    //width: 95%;\r\n    width: min(95%, 144rem); //igual que las 2 lineas de arriba...  menor a 1200px toma 95% y mayor a 1200px muestra los 1200ox\r\n    margin: 0 auto;\r\n}\r\n\r\n@mixin contenedor100{\r\n    width: min(100%, 144rem);\r\n    margin: 0 auto;\r\n}\r\n\r\n@mixin contenedor-sm{\r\n    width: min(95%, 60rem); \r\n    margin: 0 auto;\r\n}\r\n\r\n@mixin contenedor-xs{\r\n    width: min(95%, 35rem); \r\n    margin: 0 auto;\r\n}\r\n\r\n@mixin texto_fluido($min, $max){\r\n    font-size: clamp($min, -0.8rem + 10vw ,$max);\r\n}\r\n\r\n/*\r\n@mixin logo{\r\n    color: v.$blanco;\r\n    text-align: center;\r\n    margin-bottom: 2rem;\r\n    @include tablet{\r\n        color: v.$azuloscuro;\r\n        text-align: left;\r\n        margin: 0;\r\n    }\r\n}*/\r\n\r\n\r\n@mixin menu-social($color, $size) {\r\n    &__enlace{ // = <a>...</a>\r\n        &::before{\r\n            color: $color;\r\n            font-size: $size;\r\n            display: inline-block; // para que se ponga el elemento al lado de otro se puede aplicar pading\r\n            font-style: normal;\r\n            text-rendering: auto; //propiedad que se aplica a vectores\r\n            -webkit-font-smoothing: antialiased;\r\n            font-family: \"Font Awesome 6 brands\";\r\n        }\r\n        &[href*=\"https://facebook.com\"]::before{\r\n            content: \"\\f39e\";\r\n        }\r\n        &[href*=\"https://github.com\"]::before{\r\n            content: \"\\f09b\";\r\n        }\r\n        &[href*=\"https://tiktok.com\"]::before{\r\n            content: \"\\e07b\";\r\n        }\r\n        &[href*=\"https://instagram.com\"]::before{\r\n            content: \"\\f16d\";\r\n        }\r\n        &[href*=\"https://twitter.com\"]::before{\r\n            content: \"\\f099\";\r\n        }\r\n        &[href*=\"https://youtube.com\"]::before{\r\n            content: \"\\f167\";\r\n        }\r\n    }\r\n    &__ocultar{ //== <span></span>\r\n        display: none;\r\n    }\r\n}","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.acciones{ //hace referencia a las etiquetas <a>href=\"\"</a> en las paginas de login/registro... etc.\r\n    margin: 2rem 1rem 1rem 1rem;\r\n    display: flex;\r\n    justify-content: space-between;\r\n    &__Centrar{\r\n        @extend .acciones;\r\n        justify-content: center;\r\n    }\r\n    &__enlace{\r\n        //color: v.$negro;\r\n        color: v.$gris80;\r\n        font-size: 1.4rem;\r\n        font-weight: v.$delgada;\r\n    }\r\n}","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.wrapper {\r\n  display: flex;\r\n}\r\n.acordeon{\r\n  max-height: 0rem;\r\n  overflow: hidden;\r\n  transition: max-height 0.3s ease-out;\r\n}\r\n\r\n.showacordeon{\r\n  max-height: 100%; \r\n}\r\n\r\n\r\n///////////////// con input tipe chekbox sin usar js, en vista cerrarcaja.php//////////////////\r\n.accordion{\r\n  margin-top: 2rem;\r\n  input[type=\"checkbox\"]{\r\n    display: none;\r\n  }\r\n  .etiqueta{\r\n    cursor: pointer;\r\n    display: block;\r\n    padding: 1rem;\r\n    font-size: 1.7rem;\r\n    text-align: center;\r\n    position: relative;\r\n    &::before{\r\n      content: \"+\";\r\n      position: absolute;\r\n      right: 0;\r\n      margin-right: 1rem;\r\n      font-size: 2rem;\r\n      font-weight: 700;\r\n    }\r\n  }\r\n  .wrapper-content{\r\n    margin-top: 1rem;\r\n    flex: 1;\r\n    max-height: 0rem;\r\n    transition: max-height 0.2s ease-out;\r\n  }\r\n  .content{\r\n    max-height: 0rem;\r\n    overflow: hidden;\r\n    transition: max-height 0.3s ease-out;\r\n  }\r\n\r\n  input[type=\"checkbox\"]:checked + .etiqueta + .wrapper{\r\n    .wrapper-content{\r\n      max-height: 100%;\r\n      .content{\r\n        max-height: 100%; \r\n      }\r\n    }\r\n  }\r\n\r\n  input[type=\"checkbox\"]:checked + .etiqueta::before{\r\n    content: \"-\";\r\n  }\r\n}\r\n\r\n\r\n///////////////// con input tipe radio sin usar js, en vista index.php de almacen tab//////////////////\r\n.accordion_inv{\r\n    #infoalmacen:checked ~ .btn_inv_info_rapido .btninfoalmacen{\r\n      background-color: darken(v.$gris20, 0);\r\n      color: v.$gris80;\r\n      border-color: lighten(v.$gris80, 10);\r\n    }\r\n    #stockproducto:checked ~ .btn_inv_info_rapido .btnstockproducto{\r\n      background-color: darken(v.$gris20, 0);\r\n      color: v.$gris80;\r\n      border-color: lighten(v.$gris80, 10);\r\n    }\r\n    #utilidadproducto:checked ~ .btn_inv_info_rapido .btnutilidadproducto{\r\n      background-color: darken(v.$gris20, 0);\r\n      color: v.$gris80;\r\n      border-color: lighten(v.$gris80, 10);\r\n    }\r\n    #sedes:checked ~ .btn_inv_info_rapido .btnsedes{\r\n      background-color: darken(v.$gris20, 0);\r\n      color: v.$gris80;\r\n      border-color: lighten(v.$gris80, 10);\r\n    }\r\n    #proveedores:checked ~ .btn_inv_info_rapido .btnproveedores{\r\n      background-color: darken(v.$gris20, 0);\r\n      color: v.$gris80;\r\n      border-color: lighten(v.$gris80, 10);\r\n    }\r\n    #ordenproduccion:checked ~ .btn_inv_info_rapido .btnordenproduccion{\r\n      background-color: darken(v.$gris20, 0);\r\n      color: v.$gris80;\r\n      border-color: lighten(v.$gris80, 10);\r\n    }\r\n    #codigobarras:checked ~ .btn_inv_info_rapido .btncodigobarras{\r\n      background-color: darken(v.$gris20, 0);\r\n      color: v.$gris80;\r\n      border-color: lighten(v.$gris80, 10);\r\n    }\r\n    .accordion_tab_content{\r\n      display: none;\r\n    }\r\n    input[type=\"radio\"]{\r\n      display: none;\r\n    }\r\n    #infoalmacen:checked ~ .tablas_inv_rapido .infoalmacen{\r\n      display: block;\r\n    }\r\n    #stockproducto:checked ~ .tablas_inv_rapido .tablastock{\r\n      display: block;\r\n    }\r\n    #utilidadproducto:checked ~ .tablas_inv_rapido .tablautilidad{\r\n      display: block;\r\n    }\r\n    #sedes:checked ~ .tablas_inv_rapido .sedes{\r\n      display: block;\r\n    }\r\n    #proveedores:checked ~ .tablas_inv_rapido .proveedores{\r\n      display: block;\r\n    }\r\n    #ordenproduccion:checked ~ .tablas_inv_rapido .ordenproduccion{\r\n      display: block;\r\n    }\r\n    #codigobarras:checked ~ .tablas_inv_rapido .codigobarras{\r\n      display: block;\r\n    }\r\n}\r\n\r\n///////////////// con input tipe radio sin usar js, en vista index.php de configuracion//////////////////\r\n.accordion_inv{\r\n  #btn1:checked ~ .btnsetup .btn1{\r\n    background-color: darken(v.$gris20, 0);\r\n    color: v.$gris80;\r\n    border-color: lighten(v.$gris80, 10);\r\n  }\r\n  #btn2:checked ~ .btnsetup .btn2{\r\n    background-color: darken(v.$gris20, 0);\r\n    color: v.$gris80;\r\n    border-color: lighten(v.$gris80, 10);\r\n  }\r\n  #btn3:checked ~ .btnsetup .btn3{\r\n    background-color: darken(v.$gris20, 0);\r\n    color: v.$gris80;\r\n    border-color: lighten(v.$gris80, 10);\r\n  }\r\n  #btn4:checked ~ .btnsetup .btn4{\r\n    background-color: darken(v.$gris20, 0);\r\n    color: v.$gris80;\r\n    border-color: lighten(v.$gris80, 10);\r\n  }\r\n  #btn5:checked ~ .btnsetup .btn5{\r\n    background-color: darken(v.$gris20, 0);\r\n    color: v.$gris80;\r\n    border-color: lighten(v.$gris80, 10);\r\n  }\r\n  #btn6:checked ~ .btnsetup .btn6{\r\n    background-color: darken(v.$gris20, 0);\r\n    color: v.$gris80;\r\n    border-color: lighten(v.$gris80, 10);\r\n  }\r\n  #btn7:checked ~ .btnsetup .btn7{\r\n    background-color: darken(v.$gris20, 0);\r\n    color: v.$gris80;\r\n    border-color: lighten(v.$gris80, 10);\r\n  }\r\n  #btn8:checked ~ .btnsetup .btn8{\r\n    background-color: darken(v.$gris20, 0);\r\n    color: v.$gris80;\r\n    border-color: lighten(v.$gris80, 10);\r\n  }\r\n  #btn9:checked ~ .btnsetup .btn9{\r\n    background-color: darken(v.$gris20, 0);\r\n    color: v.$gris80;\r\n    border-color: lighten(v.$gris80, 10);\r\n  }\r\n  #btn10:checked ~ .btnsetup .btn10{\r\n    background-color: darken(v.$gris20, 0);\r\n    color: v.$gris80;\r\n    border-color: lighten(v.$gris80, 10);\r\n  }\r\n  #btn11:checked ~ .btnsetup .btn11{\r\n    background-color: darken(v.$gris20, 0);\r\n    color: v.$gris80;\r\n    border-color: lighten(v.$gris80, 10);\r\n  }\r\n  #btn12:checked ~ .btnsetup .btn12{\r\n    background-color: darken(v.$gris20, 0);\r\n    color: v.$gris80;\r\n    border-color: lighten(v.$gris80, 10);\r\n  }\r\n  #btn13:checked ~ .btnsetup .btn13{\r\n    background-color: darken(v.$gris20, 0);\r\n    color: v.$gris80;\r\n    border-color: lighten(v.$gris80, 10);\r\n  }\r\n  #btn14:checked ~ .btnsetup .btn14{\r\n    background-color: darken(v.$gris20, 0);\r\n    color: v.$gris80;\r\n    border-color: lighten(v.$gris80, 10);\r\n  }\r\n  #btn1:checked ~ .flex .btnsetup-precios .btn1{\r\n    background: linear-gradient(\r\n        135deg,\r\n        #6366f1,\r\n        #4f46e5\r\n    );\r\n    color: #fff;\r\n    border-color: #4f46e5;\r\n    transform: translateY(-1px);\r\n    box-shadow:\r\n        0 8px 20px rgba(79,70,229,.20);\r\n    border-radius: .65rem;\r\n    transform: translateY(-1px);\r\n  }\r\n  #btn2:checked ~ .flex .btnsetup-precios .btn2{\r\n    background: linear-gradient(\r\n        135deg,\r\n        #6366f1,\r\n        #4f46e5\r\n    );\r\n    color: #fff;\r\n    border-color: #4f46e5;\r\n    transform: translateY(-1px);\r\n    box-shadow:\r\n        0 8px 20px rgba(79,70,229,.20);\r\n    border-radius: .65rem;\r\n    transform: translateY(-1px);\r\n  }\r\n  #btn3:checked ~ .flex .btnsetup-precios .btn3{\r\n    background: linear-gradient(\r\n        135deg,\r\n        #6366f1,\r\n        #4f46e5\r\n    );\r\n    color: #fff;\r\n    border-color: #4f46e5;\r\n    transform: translateY(-1px);\r\n    box-shadow:\r\n        0 8px 20px rgba(79,70,229,.20);\r\n    border-radius: .65rem;\r\n    transform: translateY(-1px);\r\n  }\r\n  #btn4:checked ~ .flex .btnsetup-precios .btn4{\r\n    background: linear-gradient(\r\n        135deg,\r\n        #6366f1,\r\n        #4f46e5\r\n    );\r\n    color: #fff;\r\n    border-color: #4f46e5;\r\n    transform: translateY(-1px);\r\n    box-shadow:\r\n        0 8px 20px rgba(79,70,229,.20);\r\n    border-radius: .65rem;\r\n    transform: translateY(-1px);\r\n  }\r\n  .btnsetup-precios label{\r\n    transition:\r\n        background .25s ease,\r\n        color .25s ease,\r\n        border-color .25s ease,\r\n        box-shadow .25s ease,\r\n        transform .25s ease;\r\n  }\r\n  .accordion_tab_content{\r\n    display: none;\r\n  }\r\n  input[type=\"radio\"]{\r\n    display: none;\r\n  } \r\n  #btn1:checked ~ .contenedorsetup .contenido1{\r\n    display: block;\r\n  }\r\n  #btn2:checked ~ .contenedorsetup .contenido2{\r\n    display: block;\r\n  }\r\n  #btn3:checked ~ .contenedorsetup .contenido3{\r\n    display: block;\r\n  }\r\n  #btn4:checked ~ .contenedorsetup .contenido4{\r\n    display: block;\r\n  }\r\n  #btn5:checked ~ .contenedorsetup .contenido5{\r\n    display: block;\r\n  }\r\n  #btn6:checked ~ .contenedorsetup .contenido6{\r\n    display: block;\r\n  }\r\n  #btn7:checked ~ .contenedorsetup .contenido7{\r\n    display: block;\r\n  }\r\n  #btn8:checked ~ .contenedorsetup .contenido8{\r\n    display: block;\r\n  }\r\n  #btn9:checked ~ .contenedorsetup .contenido9{\r\n    display: block;\r\n  }\r\n  #btn10:checked ~ .contenedorsetup .contenido10{\r\n    display: block;\r\n  }\r\n  #btn11:checked ~ .contenedorsetup .contenido11{\r\n    display: block;\r\n  }\r\n  #btn12:checked ~ .contenedorsetup .contenido12{\r\n    display: block;\r\n  }\r\n  #btn13:checked ~ .contenedorsetup .contenido13{\r\n    display: block;\r\n  }\r\n  #btn14:checked ~ .contenedorsetup .contenido14{\r\n    display: block;\r\n  }\r\n}\r\n\r\n.blockInputRadio{\r\n  input[type=\"radio\"]{\r\n    display: block;\r\n  }\r\n}","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.alerta{\n    align-items: center;\n    border: .1rem solid transparent;\n    border-radius: 1.4rem;\n    box-shadow: 0 1.8rem 4rem rgba(15, 23, 42, .08);\n    display: flex;\n    gap: 1.2rem;\n    margin: 1rem 0;\n    overflow: hidden;\n    padding: 1.2rem 1.4rem;\n    position: relative;\n    text-transform: none;\n\n    &::before{\n        bottom: 0;\n        content: '';\n        left: 0;\n        position: absolute;\n        top: 0;\n        width: .4rem;\n    }\n\n    &__icono{\n        align-items: center;\n        border-radius: 1.2rem;\n        display: inline-flex;\n        flex: 0 0 3.8rem;\n        height: 3.8rem;\n        justify-content: center;\n        width: 3.8rem;\n\n        i{\n            font-size: 1.8rem;\n        }\n    }\n\n    &__contenido{\n        display: flex;\n        flex-direction: column;\n        gap: .2rem;\n        min-width: 0;\n\n        strong{\n            color: #0f172a;\n            font-size: 1.35rem;\n            font-weight: 800;\n            line-height: 1.2;\n        }\n\n        span{\n            font-size: 1.25rem;\n            font-weight: 700;\n            line-height: 1.35;\n        }\n    }\n\n    p{\n        margin: 0;\n\n        i{\n            font-size: 1.6rem;\r\n            margin-right: 1rem;\r\n        }\r\n    }\n    &__error{\n        background: linear-gradient(135deg, rgba(255, 241, 242, .98), rgba(255, 255, 255, .96));\n        border-color: #fecdd3;\n        color: #be123c;\n\n        &::before{\n            background: #ef4444;\n        }\n\n        .alerta__icono{\n            background: #ffe4e6;\n            color: #e11d48;\n        }\n    }\n    &__exito{\n        background: linear-gradient(135deg, rgba(236, 253, 245, .98), rgba(255, 255, 255, .96));\n        border-color: #a7f3d0;\n        color: #047857;\n\n        &::before{\n            background: #10b981;\n        }\n\n        .alerta__icono{\n            background: #d1fae5;\n            color: #059669;\n        }\n    }\n}\n","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.sweetbtnconfirm{  //clase de sweetalert2\r\n    font-size: 1.4rem !important;\r\n    color: v.$blanco !important;\r\n    background-color: v.$turquesa !important;\r\n}\r\n.sweetbtncancel{\r\n    font-size: 1.4rem !important;\r\n    color: v.$blanco !important;\r\n    background-color: v.$gris50 !important;\r\n}\r\n\r\n///clase interna de sweetalert2 corresponde al icono del success\r\n.swal2-success-ring{\r\n    border: 0.25em solid v.$azul60 !important;\r\n}\r\n.swal2-success-line-long, .swal2-success-line-tip{\r\n    background-color: v.$azul60 !important;\r\n}\r\n\r\n.swal2-confirm{ //clase interna de sweetalert es el boton ok despues de confirmar\r\n    background-color: v.$turquesa !important;\r\n    font-size: 1.2rem !important;\r\n}\r\n.swal2-cancel{\r\n    font-size: 1.2rem !important;\r\n}\r\n\r\n.swal2-title{  //titulo = title\n    padding-top: 2rem !important;\n}\n\n.swal2-popup.j2-confirm {\n  width: min(46rem, calc(100vw - 3.2rem)) !important;\n  padding: 0 !important;\n  border: .1rem solid rgba(226, 232, 240, .95) !important;\n  border-radius: 1.8rem !important;\n  background: #fff !important;\n  box-shadow: 0 2.4rem 7rem rgba(15, 23, 42, .22), 0 .8rem 2rem rgba(15, 23, 42, .08) !important;\n  overflow: hidden !important;\n}\n\n.j2-confirm::before {\n  content: '';\n  display: block;\n  height: .6rem;\n  background: linear-gradient(90deg, #4f46e5, #08c6bd);\n}\n\n.j2-confirm .j2-confirm__icon {\n  display: grid !important;\n  place-items: center !important;\n  width: 6rem !important;\n  height: 6rem !important;\n  margin: 3rem auto 1.6rem !important;\n  border: 0 !important;\n  border-radius: 1.8rem !important;\n  background: #eef2ff !important;\n  color: #4f46e5 !important;\n  box-shadow: 0 1.4rem 3rem rgba(79, 70, 229, .18) !important;\n}\n\n.j2-confirm .swal2-icon-content {\n  color: inherit !important;\n  font-size: 3.2rem !important;\n  font-weight: 800 !important;\n}\n\n.j2-confirm .j2-confirm__title {\n  margin: 0 !important;\n  padding: 0 3.2rem !important;\n  color: #0f172a !important;\n  font-size: 2.25rem !important;\n  font-weight: 900 !important;\n  line-height: 1.15 !important;\n}\n\n.j2-confirm .j2-confirm__text {\n  margin: 1rem auto 0 !important;\n  padding: 0 3.8rem !important;\n  max-width: 38rem;\n  color: #64748b !important;\n  font-size: 1.45rem !important;\n  font-weight: 500 !important;\n  line-height: 1.45 !important;\n}\n\n.j2-confirm .j2-confirm__actions {\n  display: grid !important;\n  grid-template-columns: 1fr 1fr;\n  gap: 1rem !important;\n  width: 100% !important;\n  margin: 2.8rem 0 0 !important;\n  padding: 1.8rem 2rem 2rem !important;\n  border-top: .1rem solid #e2e8f0;\n  background: #f8fafc;\n}\n\n.j2-confirm .j2-confirm__button {\n  align-items: center;\n  border: 0;\n  border-radius: 1rem !important;\n  display: inline-flex !important;\n  font-size: 1.45rem !important;\n  font-weight: 800 !important;\n  height: 4.4rem;\n  justify-content: center;\n  margin: 0 !important;\n  padding: 0 1.8rem !important;\n  transition: transform .18s ease, box-shadow .18s ease, background-color .18s ease;\n}\n\n.j2-confirm .j2-confirm__button:hover {\n  transform: translateY(-.1rem);\n}\n\n.j2-confirm .j2-confirm__button--confirm {\n  background: linear-gradient(135deg, #14b8a6, #08c6bd) !important;\n  box-shadow: 0 1.2rem 2.4rem rgba(20, 184, 166, .24) !important;\n  color: #fff !important;\n}\n\n.j2-confirm .j2-confirm__actions--single {\n  grid-template-columns: minmax(14rem, 22rem) !important;\n  justify-content: center !important;\n}\n\n.j2-confirm .j2-confirm__button--cancel {\n  background: #eef2f7 !important;\n  color: #475569 !important;\n}\n\n.j2-confirm--dispatch .j2-confirm__icon::before {\n  content: \"\\f0d1\";\n  font-family: \"Font Awesome 6 Free\";\n  font-size: 2.6rem;\n  font-weight: 900;\n  line-height: 1;\n}\n\n.j2-confirm--dispatch .swal2-icon-content {\n  display: none !important;\n}\n\n.swal2-popup.j2-confirm--success::before {\n  background: linear-gradient(90deg, #14b8a6, #4f46e5);\n}\n\n.j2-confirm--success .j2-confirm__icon {\n  background: #ecfdf5 !important;\n  color: #059669 !important;\n  box-shadow: 0 1.4rem 3rem rgba(5, 150, 105, .16) !important;\n}\n\n.j2-confirm--success .swal2-icon-content {\n  color: inherit !important;\n  font-size: 3rem !important;\n}\n\n.swal2-popup.j2-confirm--danger::before {\n  background: linear-gradient(90deg, #ef4444, #f97316);\n}\n\n.j2-confirm--danger .j2-confirm__icon {\n  background: #fef2f2 !important;\n  color: #dc2626 !important;\n  box-shadow: 0 1.4rem 3rem rgba(220, 38, 38, .16) !important;\n}\n\n.j2-confirm--danger .swal2-icon-content {\n  color: inherit !important;\n  font-size: 3rem !important;\n}\n\n.j2-confirm--danger .j2-confirm__text strong {\n  color: #0f172a;\n  font-weight: 800;\n}\n\n.j2-confirm .j2-confirm__button--danger {\n  background: linear-gradient(135deg, #ef4444, #dc2626) !important;\n  box-shadow: 0 1.2rem 2.4rem rgba(220, 38, 38, .24) !important;\n  color: #fff !important;\n}\n\n.j2-confirm .j2-confirm__button--danger:hover {\n  box-shadow: 0 1.4rem 2.8rem rgba(220, 38, 38, .30) !important;\n}\n\n@media (max-width: 640px) {\n  .swal2-popup.j2-confirm {\n    width: calc(100vw - 2.4rem) !important;\n    border-radius: 1.5rem !important;\n  }\n\n  .j2-confirm .j2-confirm__title {\n    padding: 0 2.4rem !important;\n    font-size: 2rem !important;\n  }\n\n  .j2-confirm .j2-confirm__text {\n    padding: 0 2.4rem !important;\n    font-size: 1.32rem !important;\n  }\n\n  .j2-confirm .j2-confirm__actions {\n    padding: 1.4rem !important;\n  }\n}\n\n.swal2-popup.j2-toast {\n  width: min(48rem, calc(100vw - 3.2rem)) !important;\n  min-height: 5.8rem !important;\n  padding: 1rem 1.45rem 1rem 1.2rem !important;\n  border: 1px solid rgba(226, 232, 240, .95) !important;\n  border-left: .5rem solid #4f46e5 !important;\n  border-radius: 1.4rem !important;\n  background: rgba(255, 255, 255, .98) !important;\n  box-shadow: 0 1.8rem 4.5rem rgba(15, 23, 42, .18), 0 .8rem 1.6rem rgba(15, 23, 42, .08) !important;\n  backdrop-filter: blur(1.2rem);\n  align-items: center !important;\n  column-gap: 1rem !important;\n}\n\n.swal2-popup.j2-toast--success {\n  border-left-color: #4338ca !important;\n}\n\n.swal2-popup.j2-toast--error {\n  border-left-color: #ef4444 !important;\n}\n\n.swal2-popup.j2-toast--warning {\n  border-left-color: #f59e0b !important;\n}\n\n.swal2-popup.j2-toast--info,\n.swal2-popup.j2-toast--question {\n  border-left-color: #4f46e5 !important;\n}\n\n.j2-toast .j2-toast__icon {\n  position: relative !important;\n  display: grid !important;\n  place-items: center !important;\n  width: 3.8rem !important;\n  height: 3.8rem !important;\n  margin: 0 !important;\n  border: 0 !important;\n  border-radius: 1.2rem !important;\n  background: #eef2ff !important;\n  color: #4f46e5 !important;\n  transform: none !important;\n}\n\n.j2-toast .j2-toast__icon::before {\n  content: \"\\f05a\";\n  font-family: \"Font Awesome 6 Free\";\n  font-size: 1.85rem;\n  font-weight: 900;\n  line-height: 1;\n}\n\n.j2-toast--success .j2-toast__icon {\n  background: #eef2ff !important;\n  color: #4338ca !important;\n}\n\n.j2-toast--success .j2-toast__icon::before {\n  content: \"\\f00c\";\n}\n\n.j2-toast--error .j2-toast__icon {\n  background: #fef2f2 !important;\n  color: #dc2626 !important;\n}\n\n.j2-toast--error .j2-toast__icon::before {\n  content: \"\\f00d\";\n}\n\n.j2-toast--warning .j2-toast__icon {\n  background: #fff7ed !important;\n  color: #d97706 !important;\n}\n\n.j2-toast--warning .j2-toast__icon::before {\n  content: \"\\f071\";\n}\n\n.j2-toast .swal2-icon-content,\n.j2-toast .swal2-success-circular-line-left,\n.j2-toast .swal2-success-circular-line-right,\n.j2-toast .swal2-success-fix,\n.j2-toast .swal2-success-line-tip,\n.j2-toast .swal2-success-line-long,\n.j2-toast .swal2-success-ring,\n.j2-toast .swal2-x-mark {\n  display: none !important;\n}\n\n.j2-toast .j2-toast__title {\n  margin: 0 0 .18rem !important;\n  padding: 0 !important;\n  color: #0f172a !important;\n  font-size: 1.5rem !important;\n  font-weight: 800 !important;\n  line-height: 1.2 !important;\n  text-align: left !important;\n}\n\n.j2-toast .j2-toast__text {\n  margin: 0 !important;\n  padding: 0 !important;\n  color: #64748b !important;\n  font-size: 1.32rem !important;\n  font-weight: 500 !important;\n  line-height: 1.25 !important;\n  text-align: left !important;\n}\n\n.j2-toast .j2-toast__progress {\n  height: .32rem !important;\n  background: rgba(79, 70, 229, .2) !important;\n}\n\n.j2-toast--success .j2-toast__progress {\n  background: rgba(67, 56, 202, .25) !important;\n}\n\n.j2-toast--error .j2-toast__progress {\n  background: rgba(239, 68, 68, .25) !important;\n}\n\n@media (max-width: 640px) {\n  .swal2-popup.j2-toast {\n    width: calc(100vw - 2.4rem) !important;\n    padding: 1rem 1.15rem !important;\n    border-radius: 1.2rem !important;\n  }\n\n  .j2-toast .j2-toast__title {\n    font-size: 1.38rem !important;\n  }\n\n  .j2-toast .j2-toast__text {\n    font-size: 1.2rem !important;\n  }\n}\n","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.tabla{\r\n    width: 100%;\r\n    border-collapse: collapse;\r\n    thead{\r\n        color: v.$gris80;\r\n        tr{\r\n            th{\r\n                border:  solid 1px darken(v.$gris20, 0);\r\n                padding: 1rem;\r\n            }\r\n        }\r\n    }\r\n    tbody{\r\n        color: v.$gris70;\r\n        text-align: center;\r\n        tr{\r\n            td{\r\n                padding: 1rem;\r\n            }\r\n            .accionestd{  //td\r\n                padding: 0;\r\n            }\r\n            .acciones-btns{\r\n                display: inline-flex;\r\n                gap: .6rem;\r\n                padding: 1rem 0;\r\n            }\r\n        } //fin tr\r\n    } //fin tbody\r\n}//fin tabla\r\n\r\n.tabla2{\r\n    width: 100%;\r\n    border-collapse: collapse;\r\n    thead{\r\n        color: v.$gris80;\r\n        tr{\r\n            th{\r\n                border:  solid 1px darken(v.$gris20, 0);\r\n                padding: 1rem;\r\n            }\r\n        }\r\n    }\r\n    tbody{\r\n        color: v.$gris70;\r\n        text-align: center;\r\n        tr{\r\n            border-bottom:  solid 1px v.$gris20;\r\n            td{\r\n                padding: 1rem;\r\n            }\r\n            .accionestd{  //td\r\n                padding: 0;\r\n            }\r\n            .acciones-btns{\r\n                display: inline-flex;\r\n                gap: .6rem;\r\n            }\r\n        } //fin tr\r\n    } //fin tbody\r\n}//fin tabla","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n//tamaño de botones\r\n.btn-xs{\r\n    display: inline-block;\r\n    width: auto;\r\n    font-size: 1.1rem;\r\n    padding: .4rem .6rem;\r\n    border-radius: .4rem;\r\n    border: 1px solid transparent;\r\n    cursor: pointer;\r\n    transition: color .15s ease-in-out,background-color .15s ease-in-out,border-color .15s ease-in-out,box-shadow .15s ease-in-out;\r\n}\r\n.btn-md{\r\n    display: inline-block;\r\n    width: auto;\r\n    font-size: 1.6rem;\r\n    padding: .5rem 1.2rem;\r\n    border-radius: .4rem;\r\n    border: 1px solid transparent;\r\n    cursor: pointer;\r\n    transition: color .15s ease-in-out,background-color .15s ease-in-out,border-color .15s ease-in-out,box-shadow .15s ease-in-out;\r\n}\r\n.btn-lg{\r\n    display: inline-block;\r\n    width: auto;\r\n    font-size: 1.7rem;\r\n    font-weight: 600;\r\n    padding: .6rem 1.4rem;\r\n    border-radius: .4rem;\r\n    border: 1px solid transparent;\r\n    cursor: pointer;\r\n    transition: color .15s ease-in-out,background-color .15s ease-in-out,border-color .15s ease-in-out,box-shadow .15s ease-in-out;\r\n}\r\n//colores de botones\r\n\r\n.btn-bluedark{\r\n    background-color:v.$azul70;\r\n    border-color:v.$azul70;\r\n    color: v.$blanco;\r\n    &:hover{\r\n        background-color: darken(v.$azul70, 15);\r\n        border-color: darken(v.$azul70, 15);\r\n    }\r\n}\r\n.btn-blueintense{\r\n    background-color:v.$azul60;\r\n    border-color:v.$azul60;\r\n    color: v.$blanco;\r\n    &:hover{\r\n        background-color: darken(v.$azul60, 15);\r\n        border-color: darken(v.$azul60, 15);\r\n    }\r\n}\r\n.btn-blue{\r\n    background-color:v.$azul40;\r\n    border-color:v.$azul40;\r\n    color: v.$blanco;\r\n    &:hover{\r\n        background-color: darken(v.$azul40, 15);\r\n        border-color: darken(v.$azul40, 15);\r\n    }\r\n}\r\n.btn-bluelight{\r\n    background-color:v.$azul20;\r\n    border-color:v.$azul20;\r\n    color: v.$blanco;\r\n    &:hover{\r\n        background-color: darken(v.$azul20, 15);\r\n        border-color: darken(v.$azul20, 15);\r\n    }\r\n}\r\n.btn-red{\r\n    background-color:v.$rojo60;\r\n    border-color:v.$rojo60;\r\n    color: v.$blanco;\r\n    &:hover{\r\n        background-color: darken(v.$rojo60, 15);\r\n        border-color: darken(v.$rojo60, 15);\r\n    }\r\n}\r\n.btn-green{\r\n    background-color:v.$verde70;\r\n    border-color:v.$verde70;\r\n    color: v.$blanco;\r\n    &:hover{\r\n        background-color: darken(v.$verde70, 15);\r\n        border-color: darken(v.$verde70, 15);\r\n    }\r\n}\r\n.btn-lima{\r\n    background-color:v.$lima;\r\n    border-color:v.$lima;\r\n    color: v.$blanco;\r\n    &:hover{\r\n        background-color: darken(v.$lima, 15);\r\n        border-color: darken(v.$lima, 15);\r\n    }\r\n}\r\n.btn-pink{\r\n    background-color:v.$rosa;\r\n    border-color:v.$rosa;\r\n    color: v.$blanco;\r\n    &:hover{\r\n        background-color: darken(v.$rosa, 15);\r\n        border-color: darken(v.$rosa, 15);\r\n    }\r\n}\r\n.btn-orange{\r\n    background-color:v.$naranja100;\r\n    border-color:v.$naranja100;\r\n    color: v.$blanco;\r\n    &:hover{\r\n        background-color: darken(v.$naranja100, 15);\r\n        border-color: darken(v.$naranja100, 15);\r\n    }\r\n}\r\n.btn-yellow{\r\n    background-color:v.$amarillo80;\r\n    border-color:v.$amarillo80;\r\n    color: v.$blanco;\r\n    &:hover{\r\n        background-color: darken(v.$amarillo80, 15);\r\n        border-color: darken(v.$amarillo80, 15);\r\n    }\r\n}\r\n.btn-turquoise{\r\n    background-color:v.$turquesa;\r\n    border-color:v.$turquesa;\r\n    color: v.$blanco;\r\n    &:hover{\r\n        background-color: darken(v.$turquesa, 15);\r\n        border-color: darken(v.$turquesa, 15);\r\n    }\r\n}\r\n.btn-indigo{\r\n    background-color:v.$indigo;\r\n    border-color:v.$indigo;\r\n    color: v.$blanco;\r\n    &:hover{\r\n        background-color: darken(v.$indigo, 15);\r\n        border-color: darken(v.$indigo, 15);\r\n    }\r\n}\r\n.btn-light{\r\n    background-color:v.$blanco;\r\n    border-color:lighten( v.$gris60, 7);\r\n    color: v.$negro90;\r\n    &:hover{\r\n        background-color: darken(v.$blanco, 15);\r\n        border-color: darken(v.$blanco, 15);\r\n    }\r\n}\r\n.btn-dark{\r\n    background-color:v.$negro90;\r\n    border-color: v.$negro90;\r\n    color: v.$blanco;\r\n    &:hover{\r\n        background-color: darken(v.$gris20, 0);\r\n        color: v.$gris80;\r\n        border-color: lighten(v.$gris80, 10);\r\n    }\r\n}\r\n.btn-semidark{\r\n    background-color:v.$gris80;\r\n    border-color: v.$gris80;\r\n    color: v.$blanco;\r\n    &:hover{\r\n        background-color: darken(v.$gris20, 0);\r\n        color: v.$gris80;\r\n        border-color: lighten(v.$gris80, 10);\r\n    }\r\n}\r\n.btn-locked{\r\n    background-color:v.$gris10;\r\n    border-color:darken(v.$gris20, 7);\r\n    color: darken(v.$gris20, 7);\r\n    &:hover{\r\n        cursor: auto;\r\n    }\r\n}\r\n.btn-command{\r\n    display: flex;\r\n    flex-direction: column;\r\n    align-items: center;\r\n    justify-content: center;\r\n    max-width: 9.6rem;\r\n    width: 100%;\r\n    padding: .7rem;\r\n    border: solid 1px v.$gris30;\r\n    border-radius: .5rem;\r\n    height: 7rem;\r\n    color: v.$gris50;\r\n    font-size: 1.25rem;\r\n    &:hover{\r\n        //background-color: v.$negro90;\r\n        color: v.$gris80;\r\n        //border-color: v.$azul40;\r\n    }\r\n}\r\n//animacion de botones de alternancia de flecha\r\n.btnrotated{\r\n    position: relative;\r\n    padding-right: 3rem;\r\n}\r\n#arrow{\r\n    position: absolute;\r\n    right: .9rem;\r\n    transition: transform 0.3s ease;\r\n}\r\n.rotated {\r\n    transform: rotate(180deg);\r\n}","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.paginacion{\r\n    text-align: center;\r\n    margin-top: 1rem;\r\n    overflow-x: scroll;\r\n    overflow-y: hidden;\r\n    &__enlace{\r\n        &--actual{\r\n            font-weight: 700;\r\n            color: v.$turquesa;\r\n            font-size: 1.7rem;\r\n        }\r\n        &--numero{\r\n            color: v.$gris80;\r\n            margin: 0 .8rem;\r\n        }\r\n        &--texto{\r\n            color: v.$gris80;\r\n        }\r\n    }\r\n}","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.stylecheckbox{\r\n    min-width: 10rem;\r\n    //white-space: nowrap;\r\n    input[type=\"checkbox\"] {\r\n        display: none;\r\n    }\r\n    input[type=\"checkbox\"] + label {\r\n        line-height: 2rem;\r\n        cursor: pointer;\r\n    }\r\n    input[type=\"checkbox\"] + label:before{ //crea una caja cuadrada con :before\r\n        content: \"\";\r\n        width: 2.2rem;\r\n        height: 2.2rem;\r\n        float: left;\r\n        border: 1px solid darken(v.$gris20, 20);\r\n        background-color: v.$blanco;\r\n        margin-right: 1rem;\r\n        border-radius: .5rem;\r\n    }\r\n    input[type=\"checkbox\"]:checked + label:before{  // cuando este chequeado toma el pseudo elemento before y pinta verde\r\n        border-color: v.$turquesa;\r\n    }\r\n    input[type=\"checkbox\"]:checked + label:after { // cuando se chequea tomo el pseudo elemento after y crea otra caja se le quita 2 bordes se rota -55º y que listo el tiket \r\n        content: \"\";\r\n        width: 1.4rem;\r\n        height: .8rem;\r\n        border: 4px solid v.$turquesa;\r\n        float: left;\r\n        margin-left: -2.8rem;\r\n        margin-top: .7rem;\r\n        border-right: 0;\r\n        border-top: 0;\r\n        transform: rotate(-55deg);\r\n    }  \r\n}\r\n\r\n///////////////////////////////////////////////////////////////////////\r\n.styleradio{\r\n    min-width: 10rem;\r\n    //white-space: nowrap;\r\n    input[type=\"radio\"] {\r\n        display: none;\r\n    }\r\n    input[type=\"radio\"] + label {\r\n        line-height: 2rem;\r\n        cursor: pointer;\r\n    }\r\n    input[type=\"radio\"] + label:before{ //crea una caja cuadrada con :before\r\n        content: \"\";\r\n        width: 2.2rem;\r\n        height: 2.2rem;\r\n        float: left;\r\n        border: 1px solid darken(v.$gris20, 20);\r\n        background-color: v.$blanco;\r\n        margin-right: 1rem;\r\n        border-radius: .5rem;\r\n    }\r\n    input[type=\"radio\"]:checked + label:before{  // cuando este chequeado toma el pseudo elemento before y pinta verde\r\n        border-color: v.$turquesa;\r\n    }\r\n    input[type=\"radio\"]:checked + label:after { // cuando se chequea tomo el pseudo elemento after y crea otra caja se le quita 2 bordes se rota -55º y que listo el tiket \r\n        content: \"\";\r\n        width: 1.4rem;\r\n        height: .8rem;\r\n        border: 4px solid v.$turquesa;\r\n        float: left;\r\n        margin-left: -2.8rem;\r\n        margin-top: .7rem;\r\n        border-right: 0;\r\n        border-top: 0;\r\n        transform: rotate(-55deg);\r\n    }\r\n}\r\n\r\n\r\n////////////////////////////////////////////////////////////////////////////////\r\n.radio-button {\r\n    //display: inline-block;\r\n    position: relative;\r\n    cursor: pointer;\r\n    .radio-button__input {\r\n        position: absolute;\r\n        opacity: 0;\r\n        width: 0;\r\n        height: 0;\r\n    }\r\n      \r\n    .radio-button__label {\r\n        display: inline-block;\r\n        padding-left: 3rem;\r\n        //margin-bottom: 1rem;\r\n        position: relative;\r\n        font-size: 1.4rem;\r\n        color: v.$blanco;\r\n        cursor: pointer;\r\n        transition: all 0.3s ease-in-out;\r\n    }\r\n      \r\n    .radio-button__span {\r\n        position: absolute;\r\n        top: 50%;\r\n        left: 0;\r\n        transform: translateY(-50%);\r\n        width: 2rem;\r\n        height: 2rem;\r\n        border-radius: 50%;\r\n        border: 2px solid v.$gris50;\r\n        transition: all 0.3s ease-in-out;\r\n    }\r\n\r\n    .radio-button__input:checked + .radio-button__label .radio-button__span {\r\n        transform: translateY(-50%) scale(0.9);\r\n        border: 5px solid v.$azul60;\r\n        color: v.$azul60;\r\n    }\r\n    .radio-button__input:checked + .radio-button__label {\r\n        color: v.$azul60;\r\n    } \r\n    .radio-button__label:hover .radio-button__span {\r\n        transform: translateY(-20%) scale(1.2);\r\n        border-color: v.$azul60;\r\n        box-shadow: 0 0 10px v.$azul60;\r\n    }\r\n}","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.midialog-sm{\r\n    &::backdrop{\r\n        background-color: v.$backdrop;\r\n    }\r\n    width: 90%;\r\n    max-width: 50rem;\r\n    border: none;\r\n    border-radius: .4rem;\r\n    .ocultar{\r\n        display: none;\r\n    }\r\n    .select2-selection__rendered{\r\n        font-size: 1.2rem;\r\n    }\r\n}\r\n.midialog-xs{\r\n    &::backdrop{\r\n        background-color: v.$backdrop;\r\n    }\r\n    width: 90%;\r\n    max-width: 32rem;\r\n    border: none;\r\n    border-radius: .4rem;\r\n}\r\n.midialog-md{\r\n    &::backdrop{\r\n        background-color: v.$backdrop;\r\n    }\r\n    width: 95%;\r\n    max-width: 60rem;\r\n    border: none;\r\n    border-radius: .4rem;\r\n}\r\n.midialog-lg{\r\n    &::backdrop{\r\n        background-color: v.$backdrop;\r\n    }\r\n    width: 95%;\r\n    max-width: 72rem;\r\n    border: none;\r\n    border-radius: .4rem;\r\n}","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.tabs{\r\n  text-align: center;\r\n  .tabs-content{\r\n      display: inline-flex;\r\n      flex-wrap: wrap;\r\n      border: 1px solid #4338ca;\r\n      padding: 0.3rem;\r\n      border-radius: 0.5rem;\r\n      label{\r\n          flex: 1 1 auto;\r\n          text-align: center;\r\n      }\r\n      input[type=\"radio\"] {\r\n          clip-path: inset(100%); //recorta el elemento\r\n          display: none; \r\n      }\r\n      label span {\r\n          display: block;\r\n          cursor: pointer;\r\n          padding: .7rem 1.2rem;\r\n          font-size: 1.3rem;\r\n          color: #4338ca;\r\n          font-weight: 400;\r\n          &:hover{\r\n              background-color: v.$azul10;\r\n          }\r\n      }\r\n      input[type=\"radio\"]:checked + span{\r\n          background-color: #4338ca;\r\n          color: v.$blanco;\r\n          border-radius: 0.5rem;\r\n          font-weight: 500;\r\n      }\r\n  }\r\n}\r\n\r\n\r\n.tabslife{\r\n  .tabslife-content{\r\n      display: flex;\r\n      flex-wrap: wrap;\r\n      margin-top: 0.5rem;\r\n      justify-content: center;\r\n      input[type=\"radio\"] {\r\n          clip-path: inset(100%); //recorta el elemento\r\n          display: none;\r\n      }\r\n      label span {\r\n          display: block;\r\n          cursor: pointer;\r\n          color: v.$gris80;\r\n          background-color: v.$blanco;\r\n          padding: .8rem 1.4rem;\r\n          border: 1px solid v.$gris20;\r\n          transition: background-color .3s ease;\r\n      }\r\n      input[type=\"radio\"]:checked + span{\r\n          background-color: darken(v.$azul10, 3);\r\n          color: #0043ed;\r\n          border-color: #0043ed;\r\n      }\r\n      label:first-child span {\r\n      border-radius: .375em 0 0 .375em;\r\n      }\r\n      label:last-child span {\r\n      border-radius: 0 .375em .375em 0;\r\n      }\r\n  }\r\n}","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.content-spinner{\r\n  position: absolute;\r\n  //z-index: 3;\r\n  width: 100%;\r\n  //height: 100vh;\r\n  height: 100%;\r\n  top: 0;\r\n  display: grid;\r\n  place-items: center;\r\n  background-color: rgba(0, 0, 0, 0.4);\r\n  overflow: hidden;\r\n}\r\n.spinner{\r\n  display: inline-block;\r\n  border: 4px solid rgba(0, 0, 0, 0.1);\r\n  width: 4rem;\r\n  height: 4rem;\r\n  border-radius: 50%;\r\n  border-left-color: v.$azul60;\r\n  animation: spinner 1s linear infinite;\r\n}\r\n\r\n\r\n\r\n.content-spinner1{\r\n  position: absolute;\r\n  //z-index: 3;\r\n  width: 100%;\r\n  //height: 100vh;\r\n  height: 100%;\r\n  top: 0;\r\n  display: grid;\r\n  place-items: center;\r\n  background-color: #eff2f79c;\r\n  overflow: hidden;\r\n}\r\n.spinner1{\r\n  display: inline-block;\r\n  border: 4px solid rgba(0, 0, 0, 0.1);\r\n  width: 4rem;\r\n  height: 4rem;\r\n  border-radius: 50%;\r\n  border-left-color: v.$azul60;\r\n  animation: spinner 1s linear infinite;\r\n  position: relative;\r\n  top: -30%;\r\n}\r\n\r\n@keyframes spinner{\r\n  0%{\r\n      transform: rotate(0deg);\r\n  }\r\n  100%{\r\n      transform: rotate(360deg);\r\n  }\r\n}",".pagination {\r\n  display: flex;\r\n  justify-content: center;\r\n  gap: 0.5rem;\r\n\r\n  li {\r\n    a {\r\n      display: inline-block;\r\n      padding: 0.5rem 1rem;\r\n      border: 1px solid #ddd;\r\n      border-radius: 0.25rem;\r\n      text-decoration: none;\r\n      color: #333;\r\n\r\n      &.disabled {\r\n        opacity: 0.4;\r\n        pointer-events: none;\r\n        cursor: default;\r\n      }\r\n\r\n      &:hover:not(.disabled) {\r\n        background-color: #f1f1f1;\r\n      }\r\n    }\r\n\r\n    &.active a {\r\n      background-color: #6366f1;\r\n      color: white;\r\n      border-color: #6366f1;\r\n    }\r\n  }\r\n}\r\n","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.content-dropdawn{\r\n    position: relative;\r\n}\r\n\r\n.btnmultiselect{\r\n    display: flex;\r\n    justify-content: space-between;\r\n    //height: 5rem;\r\n    align-items: center;\r\n    padding: 1rem 1.2rem;\r\n    border-radius: 1rem;\r\n    cursor: pointer;\r\n    background-color: v.$blanco;\r\n    max-width: 32rem;\r\n    //min-width: 26rem;\r\n    .btnmultiselect-text{\r\n        font-size: 1.5rem;\r\n        font-weight: 400;\r\n        color: v.$gris70;\r\n        margin-right: 1rem;\r\n    }\r\n    .arrow{\r\n        display: flex;\r\n        justify-content: center;\r\n        align-items: center;\r\n        height: 2.2rem;\r\n        width: 2.2rem;\r\n        background-color: v.$azul50;\r\n        border-radius: 50%;\r\n        color: v.$blanco;\r\n        transition: 0.3s;\r\n    }\r\n\r\n    &.open~ .list-items{\r\n            display: block;\r\n    }\r\n\r\n     &.open .arrow{\r\n        transform: rotate(-180deg);\r\n     } \r\n    \r\n}\r\n\r\n.list-items{\r\n    display: none;\r\n    min-width: 26.3rem;\r\n    max-width: 32rem;\r\n    position: absolute;\r\n    z-index: 15;\r\n    margin-top: 1.4rem;\r\n    background-color: v.$blanco;\r\n    border-radius: 1rem;\r\n    padding: 2rem 1.5rem 0rem 1.5rem;\r\n    .item{\r\n        height: 4rem;\r\n        color: v.$gris70;\r\n    }\r\n}\r\n","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.lineaencabezado {\r\n    font-family: v.$fuente-secundaria;\r\n    background-color: v.$azul100;\r\n    padding: 1.1rem 3rem;\r\n    color:v.$azul0;\r\n    text-align: center;\r\n    text-transform: uppercase;\r\n    font-weight: 400;\r\n    h1 {\r\n        font-size: 2.5rem;\r\n    }\r\n}\r\n.mensajetitulo {\r\n    @include m.desktop { \r\n        padding: 0 13rem;\r\n    }\r\n}\r\n.auth{\r\n    \r\n    /*max-width: 35rem;\r\n    width: 100%;\r\n    margin: 0 auto;*/\r\n    // padding: 2rem;\r\n    &__mensaje {\r\n        margin: 0 1.5rem;\r\n        @include m.desktop { \r\n            padding: 0 13rem;\r\n        }\r\n        p {\r\n            text-align: justify;\r\n            line-height: 1.4;\r\n        }\r\n    }\r\n    h2 {\r\n        margin: 1rem 1.5rem 2rem 1.5rem;\r\n    }\r\n    &__btnatras{\r\n        background-color: v.$gris50;\r\n        color: v.$blanco;\r\n        padding: 1rem 2rem;\r\n        border-radius: .35rem;\r\n        &:hover {\r\n            background-color: v.$azul100;\r\n        }\r\n    }\r\n    &__logocliente {\r\n        width: 15rem;\r\n    }\r\n    &__heading{\r\n        margin-top: 1rem;\r\n        color: v.$azul100;\r\n        text-transform: uppercase;\r\n    }\r\n    &__texto{\r\n        margin-top: 0rem;\r\n        color: v.$gris50;\r\n    }\r\n    .formulario{\r\n\r\n        &__campo{\r\n            gap: .3rem;\r\n            margin-bottom: 1.1rem;\r\n        }\r\n        &__label{\r\n            font-size: 1.4rem;\r\n        }\r\n        &__input{\r\n            padding: 1.5rem 1rem;\r\n        }\r\n    }\r\n}\r\n.bloqueauth {\r\n    display: flex;\r\n    flex-direction: column;\r\n    align-items: stretch;\r\n    justify-content: center;\r\n    width: 100%;\r\n    position: relative;\r\n    margin-top: -4rem;\r\n    z-index: 103;\r\n    @include m.telefonomini { \r\n        margin-top: 0;\r\n    }\r\n\r\n    // height: 100%;\r\n    @include m.tablet { \r\n        padding: 0 4rem; \r\n    }\r\n    @include m.desktop { \r\n        padding: 0 7rem;\r\n    }\r\n    &__btnregresar {\r\n       max-width: 11rem;\r\n       margin-top: 1rem;\r\n       margin-left: 1rem;\r\n       text-align: center;\r\n       padding: 1.5rem 0;\r\n    }\r\n    &__logocliente {\r\n        align-items: center;\r\n        max-width: 17rem;\r\n        margin: 3rem auto 1.3rem auto;\r\n    }\r\n    \r\n    &__logosinslider {\r\n        margin: 6rem auto 1.3rem auto;\r\n    }\r\n    \r\n    &__iniciarsesion {\r\n        color: v.$azul100;\r\n        text-align: center;\r\n        text-transform: capitalize;\r\n        font-size: 2.5rem;\r\n    }\r\n    &__subtitulo {\r\n        text-align: center;\r\n        margin-top: 1.2rem;\r\n    }\r\n}\r\n\r\n.bloqueformulario {\r\n    margin: 0 2.2rem;\r\n    @include m.desktop { \r\n        padding: 0 20rem;\r\n    }\r\n}\r\n.slider {\r\n    overflow: hidden;\r\n    // position: relative;\r\n    &__contenido {\r\n        padding: 0;\r\n        margin: 0;\r\n        \r\n    }\r\n    &__slide1 {\r\n        background-image: url(/build/img/slider1.jpg);\r\n    }\r\n    &__slide2 {\r\n        background-image: url(/build/img/slider2.jpg);\r\n    }\r\n    &__slide {\r\n        flex-shrink: 0;\r\n        position: relative;\r\n        width: 100%;\r\n        height: 4vh;\r\n        transition-property: transform;\r\n        background-repeat: no-repeat;\r\n        background-size: cover;\r\n        background-position : 0px -63px;\r\n        @include m.telefono { \r\n            height: 0vh;  \r\n        }\r\n        @include m.tablet { \r\n            display: none;\r\n        }\r\n    }\r\n}\r\n.slider {\r\n    &__contenido {\r\n        display: flex;\r\n        flex-direction: column;\r\n        align-items: center;\r\n        justify-content: center;\r\n        li {\r\n            font-size: 3rem;\r\n            color: v.$blanco;\r\n            background-color: v.$blanco;\r\n            text-align: center;\r\n            align-items: center;\r\n            justify-content: center;\r\n        }\r\n    }\r\n}\r\n\r\n","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n\r\n.dashboard{\r\n    &.swal2-height-auto{  //clase interna que se agrega por js de sweetalert  una espacion al final con esto se quita\r\n        height: 100% !important;\r\n    }\r\n    \r\n    background-color: v.$azul0;\r\n    @include m.tablet{\r\n        display: flex;\r\n        height: 100vh;\r\n    }\r\n    .principal{ //clase esta en header_dashboard.php\n        background-color: v.$blanco;\n        flex: 1;\n        overflow: hidden;\n    }\n    .contenido{  //clase esta en header_dashboard.php\n        background-color: v.$azul0;\n        padding: 1rem 1.6rem 2rem 1.6rem;\n        height: 94%;\n        overflow: auto;\n    }\n\r\n    /*.formulario{\r\n\r\n        input:not([type=\"submit\"]){\r\n            background-color: v.$blanco;\r\n        }\r\n        input[type=\"submit\"]{\r\n            @include m.boton(v.$indigo, v.$blanco);\r\n            text-transform: uppercase;\r\n            padding: 1rem;\r\n            font-size: 1.4rem;\r\n            font-weight: bold;\r\n        }\r\n    }*/\r\n\r\n    .enlace{\r\n        color: v.$indigo;\r\n        &:hover{\r\n            cursor: pointer;\r\n            color: darken(v.$indigo, 20%);\r\n        }\r\n\r\n    }\r\n\r\n//////////////////////////estilos al sidebar.php////////////////////////////\r\n    .sidebar{\r\n        transition: .5s all ease;\r\n        display: none;  //me oculta el sidebar lateral en dipositivo movil\r\n        overflow: hidden;\r\n        @include m.tablet{  //cuando es igual o superior a tablet muesta el sidebar lateral\r\n            display: block;\r\n            width: 9.6rem;\n        }\r\n        \r\n        background-color: v.$indigo;\n        background-image: linear-gradient(180deg, #4f46e5 0%, #4338ca 48%, #312e81 100%);\n        //padding: 2rem 0rem 2rem 2rem;\r\n        padding: 2rem 1.2rem;\n        &:hover,\n        &.sidebar-fija{\n            padding: 2rem;\n            width: 26rem;\n        }\n        &.mostrar{   //clase hecha en app.js\r\n            display: block;\r\n        }\r\n        .uptask{  //clase del h1 y de la x cerraren dispositivo movil\n            height: 7rem;\n            padding: 0;\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            h1{\r\n                color: v.$blanco;\r\n                margin: 0;\r\n                text-align: center;\r\n            }\r\n            .menux{\r\n                img{ \r\n                    width: 1.8rem;\r\n                    &:hover{\r\n                        cursor: pointer;\r\n                    }\r\n                }\r\n                @include m.tablet{\r\n                    display: none;\r\n                }\n            }\n        }\n        .sidebar-mini-logo{\n            background-color: rgba(255, 255, 255, .08);\n            border: 1px solid rgba(255, 255, 255, .20);\n            border-radius: 1.2rem;\n            display: block;\n            height: 5.8rem;\n            object-fit: contain;\n            padding: .35rem;\n            width: 5.8rem;\n        }\n        #logoj2{\n            display: none;\n            opacity: 0;\n            transform: scale(.85);\n            transition: opacity 300ms ease, transform 300ms ease;\n        }\n\n        &:hover,\n        &.sidebar-fija{\n            .uptask{\n                padding: 0 3rem;\n                justify-content: space-between;\n            }\n            .sidebar-mini-logo{\n                display: none;\n            }\n            #logoj2{\n                display: block;\n                opacity: 1;\n                transform: scale(1);\n            }\n        }\n\n        .noneElement{ //clase agregada en app.ts\n            display: none;\n        }\n        \r\n        &.minsidebar{ //clase agregada en app.ts\r\n            width: 8.5rem;\r\n        }\r\n\r\n        .sidebar-nav{\n            margin-top: 3.2rem;\n            a{              //el tamaÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬ÃƒÂ¢Ã¢â‚¬Å¾Ã‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¾Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â±o de las letras de los links a esta definido en globales.scss de 1.6rem\r\n                white-space: nowrap;\r\n                color: v.$gris30; //blanco\r\n                display: block;\r\n                margin-bottom: .8rem;\r\n                padding: 1.2rem;\n                transition-property: background-color;\r\n                transition-duration: 300ms;\n                font-size: 1.4rem;\n                text-align: center;\n                overflow: hidden;\n                .material-symbols-outlined{\n                    font-size: 2.9rem;\n                    min-width: 2.9rem;\n                }\n                label{\n                    cursor: pointer;\n                    max-width: 0;\n                    opacity: 0;\n                    overflow: hidden;\n                    transition: max-width 300ms ease, opacity 200ms ease;\n                }\n                &:hover{\n                    background-color: rgba(255, 255, 255, .14);\n                    border-radius: 0.5rem;\n                    color: v.$gris30;\n                }\n                &.activo{\n                    background-color: v.$azul0;\n                    border-radius: 0.5rem;\n                    color: v.$indigo;\n                }\n                @include m.tablet{\n                    display: flex;\n                    align-items: center;\n                    justify-content: center;\n                    gap: 0;\n                    font-size: 1.2rem;\n                    margin-bottom: .8rem;\n                    min-height: 5.4rem;\n                    text-align: left;\n                }\n            }\n        }\n\n        &:hover,\n        &.sidebar-fija{\n            .sidebar-nav{\n                margin-top: 5rem;\n                a{\n                    label{\n                        max-width: 16rem;\n                        opacity: 1;\n                    }\n                    @include m.tablet{\n                        justify-content: flex-start;\n                        gap: .5rem;\n                    }\n                }\n            }\n        }\n    \r\n    \r\n        .cerrar-sesion-mobile{  //clase al boton cerrar sesion que esta en el sidebar barra lateral\r\n            margin-top: 10rem;\r\n            @include m.tablet{\r\n               display: none;\r\n            }\r\n            p{\r\n                text-align: center;\r\n                margin: 0;\r\n                font-size: 1.4rem;\r\n                color: v.$cyan;\r\n                span{\r\n                    color: v.$blanco;\r\n                    font-weight: 700;\r\n                }\r\n            }\r\n            .cerrar-sesion{\r\n                @include m.boton(v.$indigo, v.$blanco);\r\n            }\r\n        }//cierre del .cerrar-sesion-mobile\r\n    \r\n    }//cierre del .sidebar\r\n\r\n\r\n\r\n    .barra-mobile{  //clase que esta en header.php, crea sub barra para ocultar los links <a> del sidebar en dispositivos moviles\n        &.ocultarmenu{\n            display: none;\n        }\n        background-color: v.$indigo;\n        margin-top: 0;\n        padding: 2rem 4rem;\n        position: sticky;\n        top: 0;\n        z-index: 25;\n        display: flex;\n        align-items: center;\n        justify-content: space-between;\n        @include m.tablet{\r\n            display: none;\r\n        }\r\n        h1{\r\n            color: v.$blanco;\r\n            margin: 0;\r\n        }\r\n        .menu{  \r\n            img{   //iamgen de los 3 botoncitos\r\n                width: .8rem;\r\n                &:hover{\r\n                    cursor: pointer;\r\n                }\r\n            }\r\n        }\n    }\n\n    .subscription-alert-wrap{\n        align-items: center;\n        flex: 1 1 auto;\n        justify-content: center;\n        min-width: 0;\n        padding: 0 1.6rem;\n    }\n\n    .subscription-alert-wrap--mobile{\n        display: flex;\n        flex: 0 0 auto;\n        margin-top: 1.2rem;\n        padding: 0;\n        width: 100%;\n    }\n\n    .subscription-alert{\n        align-items: center;\n        background: linear-gradient(135deg, #fff7ed 0%, #fff1f2 100%);\n        border: .1rem solid #fecaca;\n        border-radius: 1.4rem;\n        box-shadow: 0 .8rem 2rem rgba(239, 68, 68, .12);\n        color: #7f1d1d;\n        cursor: pointer;\n        display: flex;\n        gap: 1rem;\n        max-width: 86rem;\n        min-height: 5.4rem;\n        overflow: hidden;\n        padding: .7rem 1.2rem .7rem .9rem;\n        position: relative;\n        text-decoration: none;\n        transition: border-color .2s ease, box-shadow .2s ease, transform .2s ease;\n        width: 100%;\n    }\n\n    .subscription-alert:hover{\n        border-color: #fb7185;\n        box-shadow: 0 1.1rem 2.6rem rgba(239, 68, 68, .18);\n        transform: translateY(-.1rem);\n    }\n\n    .subscription-alert::before{\n        background: linear-gradient(180deg, #ef4444, #f97316);\n        content: \"\";\n        height: 100%;\n        left: 0;\n        position: absolute;\n        top: 0;\n        width: .35rem;\n    }\n\n    .subscription-alert__icon{\n        align-items: center;\n        background: #fee2e2;\n        border-radius: 1rem;\n        color: #dc2626;\n        display: inline-flex;\n        flex: 0 0 3.2rem;\n        font-size: 2rem;\n        height: 3.2rem;\n        justify-content: center;\n        width: 3.2rem;\n    }\n\n    .subscription-alert__body{\n        align-items: flex-start;\n        display: flex;\n        flex-direction: column;\n        gap: .2rem;\n        min-width: 0;\n        overflow: hidden;\n    }\n\n    .subscription-alert__title{\n        color: #991b1b;\n        font-size: 1.25rem;\n        font-weight: 900;\n        line-height: 1.15;\n        max-width: 100%;\n        overflow: hidden;\n        text-overflow: ellipsis;\n        white-space: nowrap;\n    }\n\n    .subscription-alert__message{\n        color: #9f1239;\n        display: -webkit-box;\n        font-size: 1.12rem;\n        font-weight: 600;\n        line-height: 1.18;\n        min-width: 0;\n        overflow: hidden;\n        white-space: normal;\n        -webkit-box-orient: vertical;\n        -webkit-line-clamp: 2;\n    }\n\n    @media (max-width: 767px){\n        .subscription-alert{\n            align-items: flex-start;\n            border-radius: 1.2rem;\n            max-width: none;\n            min-height: auto;\n            padding: .8rem 1rem;\n        }\n\n        .subscription-alert__body{\n            align-items: flex-start;\n            flex-direction: column;\n            gap: .2rem;\n        }\n\n        .subscription-alert__message{\n            display: -webkit-box;\n            overflow: hidden;\n            white-space: normal;\n            -webkit-box-orient: vertical;\n            -webkit-line-clamp: 2;\n        }\n    }\n\n    .menu-mobile-bottom{\n        display: block;\n\n        @include m.tablet{\n            display: none;\n        }\n    }\n    \n///////////////////////estilos al header.php /////////////////////////////\n    .barra{\r\n        display: none;\r\n        background-color: v.$blanco;\r\n        /*background: rgb(239,242,247);\r\n        background: linear-gradient(90deg, rgba(239,242,247,1) 2%, rgba(255,255,255,1) 13%);*/\r\n        padding: 1rem 2rem;\r\n        box-shadow: 1px 12px 9px -13px rgba(0, 0, 0, .4);\r\n        @include m.tablet{\r\n            display: flex;\r\n            justify-content: space-between;\r\n            align-items: center;\r\n        }\r\n        .toggleanduser{\r\n            display: flex;\r\n            align-items: center;\r\n            gap: 1rem;\r\n            .sidebartoggle{\r\n                cursor: pointer;\r\n            }\r\n         