{\n  content: none !important;\n  display: none !important;\n}\n.ventas-action-btn{\n    align-items: center;\n    display: inline-flex !important;\n    font-size: 1.6rem !important;\n    font-weight: 600;\n    gap: .7rem;\n    height: 3.5rem !important;\n    justify-content: center;\n    line-height: 1.15;\n    min-height: 3.5rem;\n    padding-bottom: 0 !important;\n    padding-top: 0 !important;\n}\n\n.ventas-action-btn i{\n    font-size: 1.6rem;\n    line-height: 1;\n}\n\n#btnguardar,\n#btnfacturar,\n#btnaplicarcredito{\n    height: 3.5rem !important;\n    min-height: 3.5rem !important;\n    padding-bottom: 0 !important;\n    padding-top: 0 !important;\n}\n\n#btnguardar span,\n#btnfacturar span,\n#btnaplicarcredito span{\n    line-height: 1 !important;\n}\n\n.ventas-datos-card{\n    background: linear-gradient(180deg, #ffffff 0%, #f8fafc 100%) !important;\n    border-color: #dbe4f0 !important;\n    border-radius: 1.2rem !important;\n    box-shadow: 0 1rem 2.4rem rgba(15, 23, 42, .05);\n}\n\n.ventas-datos-label{\n    color: #334155 !important;\n    font-size: 1.25rem !important;\n    font-weight: 700 !important;\n    letter-spacing: 0 !important;\n}\n\n.ventas-datos-field{\n    background-color: #f8fafc;\n    border: .1rem solid #dbe4f0;\n    border-radius: 1rem;\n    padding: .45rem .55rem .45rem 1rem;\n    transition: border-color .2s ease, box-shadow .2s ease, background-color .2s ease;\n}\n\n.ventas-datos-field:focus-within{\n    background-color: #ffffff;\n    border-color: #6366f1;\n    box-shadow: 0 0 0 .32rem rgba(99, 102, 241, .14);\n}\n\n.ventas-datos-field .material-symbols-outlined{\n    align-items: center;\n    background-color: #eef2ff;\n    border-radius: .8rem;\n    color: #4f46e5;\n    display: inline-flex;\n    flex: 0 0 3.4rem;\n    height: 3.4rem;\n    justify-content: center;\n    width: 3.4rem;\n}\n\n.ventas-datos-control{\n    background-color: #ffffff !important;\n    border-color: #cbd5e1 !important;\n    border-radius: .95rem !important;