;\n    border-radius: 999px;\n    box-shadow: 0 .7rem 1.6rem rgba(34, 197, 94, .28);\n    color: #ffffff;\n    content: \"\\f00c\";\n    display: flex;\n    font-family: \"Font Awesome 6 Free\";\n    font-size: 1.35rem;\n    font-weight: 900;\n    height: 2.8rem;\n    justify-content: center;\n    line-height: 1;\n    position: absolute;\n    right: .8rem;\n    top: .8rem;\n    width: 2.8rem;\n    z-index: 2;\n}\n\n#facturarA.ventas-action-btn{\n    background: #ffffff;\n    border-color: #cbd5e1;\n    box-shadow: 0 2px 6px rgba(15, 23, 42, .08);\n    color: #0f172a;\n}\n\n#facturarA.ventas-action-btn:hover{\n    background: #f8fafc;\n    border-color: #94a3b8;\n    box-shadow: 0 8px 18px rgba(15, 23, 42, .10);\n}\n\n@include m.desktop{\n    .ventas-actions-grid{\n        grid-template-columns: repeat(3, minmax(0, 1fr)) !important;\n    }\n\n    .ventas-action-adquiriente{\n        grid-column: auto !important;\n    }\n}\n\n#addcliente.cliente-required-pulse{\n    animation: clienteRequiredPulse 1.05s ease-in-out 3;\n    border-color: #f59e0b !important;\n    box-shadow: 0 0 0 .35rem rgba(245, 158, 11, .18), 0 1rem 2.4rem rgba(15, 23, 42, .12) !important;\n}\n\n#addcliente.cliente-required-pulse #iconCliente{\n    background: #fff7ed !important;\n    color: #d97706 !important;\n}\n\n#addcliente.cliente-required-pulse #badgeEstado{\n    background: #fff7ed !important;\n    color: #b45309 !important;\n}\n\n@keyframes clienteRequiredPulse{\n    0%, 100%{\n        transform: translateY(0);\n        box-shadow: 0 0 0 .18rem rgba(245, 158, 11, .12), 0 .4rem 1rem rgba(15, 23, 42, .08);\n    }\n    50%{\n        transform: translateY(-.2rem);\n        box-shadow: 0 0 0 .48rem rgba(245, 158, 11, .26), 0 1.2rem 2.8rem rgba(15, 23, 42, .14);\n    }\n}\n","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n\r\n//////////////////////////////----//////////////////////////////\r\n\r\n.clientes{\r\n    background-color: v.$blanco;\r\n    padding: 1rem;\r\n    &__contenedor{\r\n        @include m.contenedor100;\r\n    }\r\n    &__acciones{\r\n        display: flex;\r\n        flex-direction: column;\r\n        margin-bottom: 1rem;\r\n        @include m.telefono{\r\n            flex-direction: row;\r\n            justify-content: space-between;\r\n        }\r\n    }\r\n\r\n    &__crear{\r\n        // align-self: center;\r\n        border-bottom: 1px solid v.$gris20;\r\n        padding-bottom: 1rem;\r\n        margin-bottom: 1rem;\r\n        @include m.telefono{\r\n            border-bottom: none;\r\n            padding: 0;\r\n            margin: 0;\r\n        }\r\n        text-align: center;\r\n     }\r\n\r\n    &__busqueda{\r\n        text-align: center;\r\n        padding-bottom: 1rem;\r\n        @include m.tablet{\r\n            border-bottom: none;\r\n            padding: 0; \r\n        }\r\n        form{\r\n            width: 24rem;\r\n            margin: 0 auto;\r\n        }\r\n        .formulario__select{\r\n            width: 100%;\r\n        }\r\n        .btn_busqueda{\r\n            margin-top: .4rem;\r\n            display: flex;\r\n            justify-content: center;\r\n            .formulario__input{\r\n                border-right: none;\r\n                border-top-right-radius: 0;\r\n                border-bottom-right-radius: 0;\r\n                outline: none;\r\n                width: 100%;\r\n                @include m.tablet{\r\n                    width: 100%;\r\n                }\r\n            }\r\n            label{\r\n                padding: 0 1rem;\r\n                display: flex;\r\n                justify-content: center;\r\n                align-items: center;\r\n                border: 1px solid darken(v.$gris20, 20);\r\n                border-top-right-radius: .5rem;\r\n                border-bottom-right-radius: .5rem;\r\n                border-left: none;\r\n            }\r\n            #busqueda{\r\n                display: none;\r\n            }\r\n        }\r\n    }\r\n\r\n    &__tabla{\r\n        overflow-x: scroll;\r\n    }\r\n}","@use 'base/variables' as v;\n@use 'base/mixins' as m;\n\n.inicio{\n  @include m.contenedor100;\n}\n\n.dashboard-home{\n  --dash-primary: #4f46e5;\n  --dash-primary-dark: #4338ca;\n  --dash-teal: #0f766e;\n  --dash-green: #059669;\n  --dash-red: #dc2626;\n  --dash-amber: #d97706;\n  --dash-border: #dbe4f0;\n  --dash-muted: #64748b;\n  --dash-text: #14233a;\n  --dash-soft: #f8fafc;\n\n  background:\n    linear-gradient(180deg, rgba(79,70,229,.06), rgba(255,255,255,0) 18rem),\n    #fff;\n  border: 1px solid var(--dash-border);\n  border-radius: .8rem;\n  box-shadow: 0 12px 28px rgba(15, 23, 42, .06);\n  color: var(--dash-text);\n  padding: 1.6rem;\n}\n\n.dashboard-home__inner{\n  display: flex;\n  flex-direction: column;\n  gap: 1.45rem;\n  min-width: 0;\n}\n\n.dashboard-home__header{\n  align-items: flex-start;\n  display: flex;\n  gap: 1rem;\n  justify-content: space-between;\n  padding-bottom: .25rem;\n}\n\n.dashboard-home__eyebrow{\n  color: var(--dash-primary);\n  font-size: 1.1rem;\n  font-weight: 800;\n  margin: 0 0 .25rem;\n  text-transform: uppercase;\n}\n\n.dashboard-home__header h1{\n  color: var(--dash-text);\n  font-size: 2.8rem;\n  font-weight: 900;\n  line-height: 1.1;\n  margin: 0;\n}\n\n.dashboard-home__subtitle{\n  color: var(--dash-muted);\n  font-size: 1.35rem;\n  margin: .35rem 0 0;\n}\n\n.dashboard-home__actions{\n  display: flex;\n  flex-wrap: wrap;\n  gap: .8rem;\n  justify-content: flex-end;\n}\n\n.dashboard-action{\n  align-items: center;\n  border-radius: .65rem;\n  cursor: pointer;\n  display: inline-flex;\n  font-size: 1.35rem;\n  font-weight: 800;\n  gap: .65rem;\n  min-height: 4.4rem;\n  padding: 0 1.3rem;\n  transition: background .2s ease, border-color .2s ease, box-shadow .2s ease, color .2s ease, transform .2s ease;\n\n  .material-symbols-outlined{\n    font-size: 2rem;\n  }\n\n  &:hover{\n    transform: translateY(-1px);\n  }\n}\n\n.dashboard-action--ghost{\n  background: #fff;\n  border: 1px solid var(--dash-border);\n  color: #263852;\n\n  &:hover{\n    border-color: rgba(79,70,229,.35);\n    box-shadow: 0 8px 18px rgba(15,23,42,.07);\n  }\n}\n\n.dashboard-action--primary{\n  background: linear-gradient(135deg, #5b52f0, var(--dash-primary-dark));\n  border: 1px solid var(--dash-primary-dark);\n  box-shadow: 0 12px 24px rgba(79,70,229,.22);\n  color: #fff;\n}\n\n.dashboard-kpis{\n  display: grid;\n  gap: 1rem;\n}\n\n.dashboard-kpis--primary{\n  grid-template-columns: repeat(4, minmax(0, 1fr));\n}\n\n.dashboard-kpis--secondary{\n  grid-template-columns: repeat(3, minmax(0, 1fr));\n}\n\n.dashboard-kpi{\n  background: #fff;\n  border: 1px solid var(--dash-border);\n  border-radius: .8rem;\n  box-shadow: 0 8px 18px rgba(15, 23, 42, .045);\n  display: flex;\n  flex-direction: column;\n  gap: .85rem;\n  min-height: 13.2rem;\n  overflow: hidden;\n  padding: 1.35rem;\n  position: relative;\n}\n\n.dashboard-kpi::before{\n  background: var(--dash-primary);\n  content: \"\";\n  height: .35rem;\n  inset: 0 0 auto;\n  position: absolute;\n}\n\n.dashboard-kpi__top{\n  align-items: center;\n  display: flex;\n  gap: .75rem;\n}\n\n.dashboard-kpi__icon{\n  align-items: center;\n  background: rgba(79,70,229,.10);\n  border-radius: .65rem;\n  color: var(--dash-primary);\n  display: inline-flex;\n  flex: 0 0 4rem;\n  font-size: 2.4rem;\n  height: 4rem;\n  justify-content: center;\n}\n\n.dashboard-kpi__label{\n  color: #526172;\n  font-size: 1.25rem;\n  font-weight: 800;\n  line-height: 1.2;\n  text-transform: uppercase;\n}\n\n.dashboard-kpi strong{\n  color: var(--dash-text);\n  display: block;\n  font-size: 2.65rem;\n  font-weight: 900;\n  line-height: 1.05;\n  overflow-wrap: anywhere;\n}\n\n.dashboard-kpi small{\n  color: var(--dash-muted);\n  font-size: 1.15rem;\n  line-height: 1.25;\n}\n\n.dashboard-kpi__pair{\n  display: grid;\n  gap: .8rem;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n}\n\n.dashboard-kpi__pair > div{\n  background: var(--dash-soft);\n  border: 1px solid #e2e8f0;\n  border-radius: .65rem;\n  padding: .85rem;\n}\n\n.dashboard-kpi__product{\n  font-size: 2rem !important;\n  line-height: 1.18 !important;\n}\n\n.dashboard-kpi--success::before{ background: var(--dash-green); }\n.dashboard-kpi--success .dashboard-kpi__icon{ background: rgba(5,150,105,.11); color: var(--dash-green); }\n.dashboard-kpi--success strong{ color: var(--dash-green); }\n\n.dashboard-kpi--primary::before{ background: var(--dash-primary); }\n.dashboard-kpi--primary strong{ color: var(--dash-primary); }\n\n.dashboard-kpi--danger::before{ background: var(--dash-red); }\n.dashboard-kpi--danger .dashboard-kpi__icon{ background: rgba(220,38,38,.10); color: var(--dash-red); }\n.dashboard-kpi--danger strong{ color: var(--dash-red); }\n\n.dashboard-kpi--warning::before{ background: var(--dash-amber); }\n.dashboard-kpi--warning .dashboard-kpi__icon{ background: rgba(217,119,6,.11); color: var(--dash-amber); }\n.dashboard-kpi--warning strong{ color: var(--dash-amber); }\n\n.dashboard-kpi--neutral::before{ background: #334155; }\n.dashboard-kpi--neutral .dashboard-kpi__icon{ background: #f1f5f9; color: #334155; }\n\n.dashboard-charts,\n.dashboard-bottom{\n  display: grid;\n  gap: 1.2rem;\n  min-width: 0;\n}\n\n.dashboard-charts{\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n}\n\n.dashboard-bottom{\n  grid-template-columns: minmax(0, 2fr) minmax(30rem, 1fr);\n  padding-bottom: 8rem;\n}\n\n.dashboard-panel{\n  background: #fff;\n  border: 1px solid var(--dash-border);\n  border-radius: .8rem;\n  box-shadow: 0 8px 18px rgba(15, 23, 42, .045);\n  min-width: 0;\n  padding: 1.35rem;\n}\n\n.dashboard-panel__head{\n  align-items: center;\n  border-bottom: 1px solid var(--dash-border);\n  display: flex;\n  gap: 1rem;\n  justify-content: space-between;\n  margin-bottom: 1.2rem;\n  padding-bottom: 1rem;\n}\n\n.dashboard-panel__head h2{\n  color: var(--dash-text);\n  font-size: 1.85rem;\n  font-weight: 900;\n  line-height: 1.15;\n  margin: 0;\n}\n\n.dashboard-panel__head p{\n  color: var(--dash-muted);\n  font-size: 1.2rem;\n  margin: .25rem 0 0;\n}\n\n.dashboard-panel__head > .material-symbols-outlined{\n  align-items: center;\n  background: rgba(79,70,229,.10);\n  border-radius: .65rem;\n  color: var(--dash-primary);\n  display: inline-flex;\n  flex: 0 0 4rem;\n  font-size: 2.35rem;\n  height: 4rem;\n  justify-content: center;\n}\n\n.dashboard-chart{\n  height: 30rem;\n  position: relative;\n  width: 100%;\n}\n\n.dashboard-chart canvas{\n  max-height: 100%;\n  width: 100% !important;\n}\n\n.dashboard-table-wrap{\n  overflow-x: auto;\n}\n\n.dashboard-table{\n  border-collapse: separate;\n  border-spacing: 0;\n  min-width: 68rem;\n  width: 100%;\n}\n\n.dashboard-table th{\n  background: #f6f8fb;\n  border-bottom: 1px solid #d5deea;\n  border-top: 1px solid #d5deea;\n  color: #26364d;\n  font-size: 1.25rem;\n  font-weight: 900;\n  padding: 1rem;\n  text-align: left;\n}\n\n.dashboard-table th:first-child{\n  border-left: 1px solid #d5deea;\n  border-radius: .55rem 0 0 .55rem;\n}\n\n.dashboard-table th:last-child{\n  border-right: 1px solid #d5deea;\n  border-radius: 0 .55rem .55rem 0;\n}\n\n.dashboard-table td{\n  border-bottom: 1px solid #e2e8f0;\n  color: #1e2d42;\n  font-size: 1.32rem;\n  padding: 1.05rem;\n}\n\n.dashboard-table td:nth-child(n+2){\n  font-weight: 700;\n  white-space: nowrap;\n}\n\n.dashboard-stock__list{\n  display: grid;\n  gap: .85rem;\n}\n\n.dashboard-stock__list li{\n  align-items: center;\n  background: var(--dash-soft);\n  border: 1px solid #e2e8f0;\n  border-radius: .7rem;\n  display: flex;\n  gap: 1rem;\n  justify-content: space-between;\n  padding: 1rem;\n}\n\n.dashboard-stock__list strong{\n  color: var(--dash-text);\n  display: block;\n  font-size: 1.35rem;\n  line-height: 1.25;\n}\n\n.dashboard-stock__list small{\n  color: var(--dash-muted);\n  display: block;\n  font-size: 1.15rem;\n  margin-top: .25rem;\n}\n\n.dashboard-stock__list b{\n  color: var(--dash-red);\n  display: block;\n  font-size: 1.6rem;\n  text-align: right;\n}\n\n@media (max-width: 1200px){\n  .dashboard-kpis--primary{\n    grid-template-columns: repeat(2, minmax(0, 1fr));\n  }\n\n  .dashboard-bottom{\n    grid-template-columns: 1fr;\n  }\n}\n\n@media (max-width: 900px){\n  .dashboard-home{\n    padding: 1.1rem;\n  }\n\n  .dashboard-home__header{\n    flex-direction: column;\n  }\n\n  .dashboard-home__actions{\n    justify-content: stretch;\n    width: 100%;\n  }\n\n  .dashboard-action{\n    flex: 1 1 14rem;\n    justify-content: center;\n  }\n\n  .dashboard-kpis--secondary,\n  .dashboard-charts{\n    grid-template-columns: 1fr;\n  }\n}\n\n@media (max-width: 640px){\n  .dashboard-home{\n    border: 0;\n    border-radius: 0;\n    padding: 1rem;\n  }\n\n  .dashboard-home__header h1{\n    font-size: 2.35rem;\n  }\n\n  .dashboard-home__subtitle{\n    font-size: 1.25rem;\n  }\n\n  .dashboard-kpis--primary{\n    grid-template-columns: 1fr;\n  }\n\n  .dashboard-kpi{\n    min-height: 0;\n    padding: 1.15rem;\n  }\n\n  .dashboard-kpi strong{\n    font-size: 2.25rem;\n  }\n\n  .dashboard-chart{\n    height: 24rem;\n  }\n\n  .dashboard-panel{\n    padding: 1.1rem;\n  }\n\n  .dashboard-panel__head{\n    align-items: flex-start;\n  }\n}","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.datos{\r\n    margin-top: 2rem;\r\n    &__contenedorgraficas{\r\n        margin-top: 0rem;\r\n        \r\n        @include m.xl_tablet{\r\n            display: flex;\r\n            gap: 1rem;\r\n        }\r\n        @include m.desktop{\r\n            gap: 1.5rem;\r\n        }\r\n        @include m.xl_desktop{\r\n            gap: 2rem;\r\n        }\r\n    }\r\n    &__grafica1{\r\n        background-color: v.$blanco;\r\n        padding: 1rem;\r\n        //flex-basis: calc(60% - 1rem);\r\n        @include m.xl_tablet{\r\n            width: 68%;\r\n        }\r\n       // @include m.contenedor-sm;\r\n       //width: 95%;\r\n        //max-width: 45rem;\r\n    }\r\n\r\n    &__completado{\r\n        //flex-basis: calc(40% - 1rem);\r\n        @include m.xl_tablet{\r\n            width: 31%;\r\n        }\r\n        background-color: v.$blanco;   \r\n    }\r\n    \r\n    &__bg{\r\n        position: relative;\r\n        height: 10rem;\r\n        background-image: url(/build/img/profile-img.png), linear-gradient(rgba(85,110,230,.25), rgba(85,110,230,.25));\r\n        background-repeat: no-repeat;\r\n        background-size: 15rem, cover;\r\n        background-position: center right;\r\n        padding: 2rem;\r\n    }\r\n    &__user{\r\n        position: absolute;\r\n        bottom: 0%;\r\n        left: 0%;\r\n        transform: translate(50%, 50%);\r\n        background-color: v.$blanco;\r\n        border-radius: 50%;\r\n        padding: 1rem;\r\n        i{\r\n            font-size: 3rem;\r\n            color: v.$gris60;\r\n        }\r\n    }\r\n    &__admininfo{\r\n        margin-top: 1.5rem;\r\n        padding: 1rem 2rem;\r\n        display: flex;\r\n        align-items: center;\r\n        gap: 2rem;\r\n    }\r\n    \r\n    &__infocompletado{\r\n        padding: 0 2rem;\r\n        display: flex;\r\n        justify-content: space-around;\r\n    }\r\n    &__texto{\r\n        .dailyearning{\r\n            color: v.$gris80;\r\n            font-weight: 600;\r\n            margin-bottom: 2rem;\r\n            @include m.texto_fluido(1.5rem, 3.4rem);\r\n        }\r\n    }\r\n        .rueda{\r\n            position: relative;\r\n                width: 120px;\r\n            @include m.xl_tablet{\r\n                width: 110px;\r\n            }\r\n            @include m.desktop{\r\n                width: 115px;\r\n            //height: 115px;\r\n            }\r\n            @include m.xl_desktop{\r\n                width: 140px;\r\n            //height: 140px;\r\n            }\r\n            .afuera{\r\n                width: 120px;\r\n                height: 120px;\r\n                @include m.xl_tablet{\r\n                    width: 110px;\r\n                    height: 110px;\r\n                }\r\n                @include m.desktop{\r\n                    width: 115px;\r\n                    height: 115px;\r\n                }\r\n                @include m.xl_desktop{\r\n                    width: 140px;\r\n                    height: 140px;\r\n                }\r\n                /*border: 1px solid #c0e3ee;*/\r\n                box-shadow: 6px 6px 10px -1px rgba(70, 70, 70, 0.15), -1px -1px 12px -3px rgba(207, 207, 207, 0.7);\r\n                border-radius: 50%;\r\n                display: flex;\r\n                justify-content: center;\r\n                align-items: center;\r\n                .adentro{\r\n                    width: 85px;\r\n                    height: 85px;\r\n                    @include m.xl_tablet{\r\n                        width: 75px;\r\n                        height: 75px;\r\n                    }\r\n                    @include m.desktop{\r\n                        width: 80px;\r\n                        height: 80px;\r\n                    }\r\n                    @include m.xl_desktop{\r\n                        width: 100px;\r\n                        height: 100px;\r\n                    }\r\n                    /*border: 1px solid #ad3434;*/\r\n                    box-shadow: inset 4px 4px 6px -1px rgba(70, 70, 70, 0.2);\r\n                    border-radius: 50%;\r\n                    display: flex;\r\n                    justify-content: center;\r\n                    align-items: center;\r\n                    .numero{\r\n                        color: v.$gris60;\r\n                        font-size: 1.6rem;\r\n                    }\r\n                }\r\n            }\r\n            circle{\r\n                fill: none;\r\n                stroke: url(#GradientColor1);\r\n                stroke-width: 14px;\r\n                stroke-dasharray: 440;\r\n                stroke-dashoffset: 440;\r\n                //animation: anim1 3s linear forwards;\r\n                transition: all 3s ease;\r\n            }\r\n             \r\n            .animacion{\r\n                //stroke-dashoffset: 88;\r\n            }\r\n            /*\r\n            @keyframes anim1{\r\n                100%{stroke-dashoffset: 88;}  //80% html\r\n            }*/\r\n        \r\n            svg{\r\n                position: absolute;\r\n                left: 0;\r\n                top: 0;\r\n            }\r\n            .name{\r\n                font-size: 1.8rem;\r\n                margin-top: 1rem;\r\n                color: v.$blanco;\r\n            }\r\n        }// fin rueda\r\n}","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.perfil{\r\n    @include m.contenedor100;\r\n    &__contenedor{\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 2rem;\r\n        @include m.xl_tablet{\r\n            flex-direction: row;\r\n        }\r\n    }\r\n    &__col1{\r\n        text-align: center;\r\n        background-color: v.$blanco;\r\n        //adding: 4rem 5rem;\r\n    }\r\n    &__img{\r\n        i{\r\n            font-size: 7rem;\r\n            background-color: rgba(85,110,230,.25);\r\n            padding: 3rem;\r\n            border-radius: 50%;\r\n            color: v.$blanco;\r\n        }\r\n        padding: 4rem 5rem 0 5rem;\r\n        border-bottom: 1px solid v.$gris20;\r\n    }\r\n    &__nombre{\r\n        font-size: 1.8rem;\r\n        color: v.$gris60;\r\n        font-weight: 600;\r\n    }\r\n    &__cuenta{\r\n        color: v.$gris50;\r\n        font-weight: 500;\r\n    }\r\n    &__contact{\r\n        padding: 3rem 2rem 0 2rem;\r\n        text-align: left;\r\n        label{\r\n            color: v.$gris50;\r\n            font-size: 1.2rem;\r\n        }\r\n    }\r\n    &__email, &__phone{\r\n        color: v.$gris60;\r\n        margin-top: .4rem;\r\n    }\r\n    \r\n    &__col2{\r\n        background-color: v.$blanco;\r\n        padding: 2rem;\r\n        flex: 1;\r\n        .cambiarpassword{\r\n            color: v.$gris80;\r\n            display: block;\r\n            text-align: end;\r\n        }\r\n    }\r\n    &__contenedorform{\r\n        @include m.contenedor-sm;\r\n    }\r\n}","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.cambiarpassword{\r\n    @include m.contenedor100;\r\n    &__contenedor{\r\n        background-color: v.$blanco;\r\n        padding: 1rem\r\n    }\r\n    &__contenido{\r\n        @include m.contenedor-sm;\r\n        padding: 1rem 0;\r\n    }\r\n}","@use 'base/variables' as v;\n@use 'base/mixins' as m;\n\n.configuracion{\n  --config-primary: #4f46e5;\n  --config-primary-dark: #4338ca;\n  --config-accent: #06b6d4;\n  --config-border: #dbe3ef;\n  --config-muted: #64748b;\n  --config-text: #14233b;\n  --config-soft: #f8fafc;\n\n  color: var(--config-text);\n\n  &.configuracion-shell{\n    background:\n      linear-gradient(180deg, rgba(79,70,229,.06), rgba(255,255,255,0) 16rem),\n      #fff;\n    border: 1px solid var(--config-border);\n    border-radius: .8rem;\n    box-shadow: 0 12px 28px rgba(15, 23, 42, .06);\n    margin: 0 auto;\n    padding: 1.6rem;\n    width: min(100%, 172rem);\n  }\n\n  .configuracion-header{\n    align-items: flex-start;\n    border-bottom: 2px solid var(--config-primary);\n    display: flex;\n    justify-content: space-between;\n    margin-bottom: 1.4rem;\n    padding-bottom: 1.2rem;\n\n    h1{\n      color: var(--config-text);\n      font-size: 2.6rem;\n      font-weight: 800;\n      line-height: 1.15;\n      margin: 0;\n    }\n  }\n\n  .configuracion-eyebrow{\n    color: var(--config-primary);\n    font-size: 1.1rem;\n    font-weight: 800;\n    letter-spacing: 0;\n    margin: 0 0 .2rem;\n    text-transform: uppercase;\n  }\n\n  .configuracion-subtitle{\n    color: var(--config-muted);\n    font-size: 1.25rem;\n    margin: .35rem 0 0;\n  }\n\n  .configuracion-tabs{\n    background: rgba(255,255,255,.94);\n    border: 1px solid var(--config-border);\n    border-radius: .8rem;\n    box-shadow: 0 8px 22px rgba(15, 23, 42, .06);\n    margin-bottom: 1.4rem;\n    overflow-x: auto;\n    padding: .8rem;\n    position: sticky;\n    top: 0;\n    z-index: 20;\n  }\n\n  .configuracion-tabs__content{\n    display: flex;\n    gap: .8rem;\n    min-width: max-content;\n  }\n\n  .configuracion-tab{\n    display: block;\n    margin: 0;\n\n    input{\n      display: none;\n    }\n\n    span{\n      align-items: center;\n      background: #fff;\n      box-sizing: border-box;\n      border: 1px solid var(--config-border);\n      border-radius: .65rem;\n      color: #263852;\n      cursor: pointer;\n      display: flex;\n      font-size: 1.22rem;\n      font-weight: 700;\n      gap: .7rem;\n      height: 4.4rem;\n      justify-content: center;\n      line-height: 1;\n      min-height: 4.4rem;\n      padding: 0 1.25rem;\n      transition: background .2s ease, border-color .2s ease, box-shadow .2s ease, color .2s ease, transform .2s ease;\n      white-space: nowrap;\n\n      i{\n        align-items: center;\n        color: var(--config-primary);\n        display: inline-flex;\n        height: 1.5rem;\n        justify-content: center;\n        font-size: 1.3rem;\n        min-width: 1.5rem;\n        text-align: center;\n      }\n\n      &:hover{\n        border-color: rgba(79,70,229,.38);\n        box-shadow: 0 8px 18px rgba(79,70,229,.10);\n        transform: translateY(-1px);\n      }\n    }\n\n    input:checked + span{\n      background: linear-gradient(135deg, #5b52f0, var(--config-primary-dark));\n      border-color: var(--config-primary-dark);\n      box-shadow: 0 12px 24px rgba(79,70,229,.22);\n      color: #fff;\n\n      i{\n        color: #fff;\n      }\n    }\n  }\n\n\n  .tabs-content label.configuracion-tab > span{\n    align-items: center;\n    box-sizing: border-box;\n    display: flex;\n    gap: .85rem;\n    height: 4.4rem;\n    justify-content: center;\n    line-height: 1;\n    padding: 0 1.25rem;\n  }\n\n  .tabs-content label.configuracion-tab > span i{\n    align-items: center;\n    display: inline-flex;\n    height: 1.6rem;\n    justify-content: center;\n    line-height: 1;\n    margin: 0;\n    min-width: 1.6rem;\n  }\n  .configuracion-content{\n    background: rgba(255,255,255,.82);\n    border: 1px solid var(--config-border);\n    border-radius: .8rem;\n    min-height: 52rem;\n    padding: 1.4rem;\n  }\n\n  .paginas{\n    min-width: 0;\n  }\n\n  .config-system{\n    align-items: flex-start;\n    display: grid;\n    gap: 1.4rem;\n    grid-template-columns: 23rem minmax(0, 1fr);\n  }\n\n  .config-system-nav{\n    background: var(--config-soft);\n    border: 1px solid var(--config-border);\n    border-radius: .8rem;\n    padding: 1.2rem;\n    position: sticky;\n    top: 8.4rem;\n    z-index: 10;\n  }\n\n  .config-system-nav__heading{\n    align-items: center;\n    border-bottom: 1px solid var(--config-border);\n    display: flex;\n    gap: .9rem;\n    margin-bottom: 1rem;\n    padding-bottom: 1rem;\n    text-align: left;\n\n    .material-symbols-outlined{\n      align-items: center;\n      background: rgba(79,70,229,.10);\n      border-radius: .65rem;\n      color: var(--config-primary);\n      display: inline-flex;\n      font-size: 2.2rem;\n      height: 3.8rem;\n      justify-content: center;\n      width: 3.8rem;\n    }\n\n    strong{\n      display: block;\n      font-size: 1.28rem;\n      line-height: 1.2;\n    }\n\n    small{\n      color: var(--config-muted);\n      display: block;\n      font-size: 1rem;\n      margin-top: .2rem;\n    }\n  }\n\n  .config-system-nav__grid{\n    display: grid;\n    gap: .75rem;\n  }\n\n  .config-system-tab{\n    align-items: center;\n    background: #fff;\n    border: 1px solid var(--config-border);\n    border-radius: .65rem;\n    color: #24364f;\n    cursor: pointer;\n    display: flex;\n    font-size: 1.16rem;\n    font-weight: 700;\n    gap: .8rem;\n    min-height: 3.9rem;\n    padding: 0 1rem;\n    text-align: left;\n    transition: background .2s ease, border-color .2s ease, box-shadow .2s ease, color .2s 