\n    100%{\n      border-color: rgba(79,70,229,.18);\n      box-shadow: 0 .8rem 1.8rem rgba(15,23,42,.06);\n    }\n  }\n\n  .config-system-content{\n    h2{\n      font-size: 2rem;\n      line-height: 1.15;\n    }\n\n    h3{\n      font-size: 1.65rem;\n      line-height: 1.18;\n    }\n\n    h4,\n    h5{\n      font-size: 1.35rem;\n      line-height: 1.18;\n    }\n\n    p,\n    small{\n      font-size: 1.05rem;\n      line-height: 1.35;\n    }\n\n    label,\n    .formulario__label{\n      font-size: 1.16rem !important;\n      line-height: 1.2 !important;\n    }\n\n    input,\n    select,\n    textarea,\n    .formulario__input{\n      font-size: 1.24rem !important;\n    }\n\n    button,\n    .btn-md{\n      font-size: 1.2rem !important;\n    }\n  }\n\n  .config-system-content .accordion_tab_content{\n    min-width: 0;\n  }\n\n  .config-system-content .accordion_tab_content{\n    background: linear-gradient(180deg, #fff 0%, #fbfdff 100%) !important;\n    border: 1px solid var(--config-border);\n    border-radius: .9rem;\n    box-shadow: 0 12px 28px rgba(15,23,42,.06);\n    padding: 1.35rem !important;\n\n    > .flex:first-child{\n      align-items: center;\n      background: #f8fafc;\n      border: 1px solid #e2e8f0;\n      border-radius: .8rem;\n      margin-bottom: 1.1rem;\n      padding: .9rem 1rem;\n\n      p{\n        align-items: center;\n        display: inline-flex;\n        gap: .55rem;\n        margin: 0;\n\n        &::before{\n          background: #eef2ff;\n          border-radius: .55rem;\n          color: var(--config-primary);\n          content: \"\\f013\";\n          display: inline-flex;\n          font-family: \"Font Awesome 6 Free\";\n          font-size: 1rem;\n          font-weight: 900;\n          height: 2.4rem;\n          justify-content: center;\n          align-items: center;\n          width: 2.4rem;\n        }\n      }\n    }\n\n    > .grid{\n      align-items: stretch;\n      gap: 1rem !important;\n\n      > div{\n        background: #f8f