ease, transform .2s ease;\n  width: 4.4rem;\n}\n\n.ordenresumen-page .ordenresumen-back:hover {\n  background: #3527bf;\n  transform: translateY(-1px);\n}\n\n.ordenresumen-actions {\n  align-items: stretch;\n  border-bottom: 2px solid #4d46e5;\n  display: flex;\n  flex-wrap: wrap;\n  gap: .9rem;\n  margin: 0 0 1.5rem;\n  padding-bottom: 1.5rem;\n}\n\n.ordenresumen-actions .btn-command {\n  background: #fff;\n  border: 1px solid #cbd7e7;\n  border-radius: .7rem;\n  color: #1f2f46;\n  font-size: 1.35rem;\n  font-weight: 600;\n  gap: .45rem;\n  height: 8rem;\n  line-height: 1.15;\n  max-width: 14.2rem;\n  min-width: 11.6rem;\n  padding: 1rem 1.1rem;\n  text-align: center;\n  transition: border-color .2s ease, box-shadow .2s ease, transform .2s ease;\n}\n\n.ordenresumen-actions .btn-command .material-symbols-outlined {\n  color: #4d46e5;\n  font-size: 2.8rem;\n}\n\n.ordenresumen-actions .btn-command:hover {\n  border-color: #8ea0ff;\n  box-shadow: 0 8px 18px rgba(79, 70, 229, .12);\n  transform: translateY(-1px);\n}\n\n.ordenresumen-actions #btnfacturar,\n.ordenresumen-actions #printcarta {\n  background: #4d3fd7;\n  border-color: #4d3fd7;\n  color: #fff;\n}\n\n.ordenresumen-actions #btnfacturar .material-symbols-outlined,\n.ordenresumen-actions #printcarta .material-symbols-outlined {\n  color: #fff;\n}\n\n.ordenresumen-actions #btneliminarorden {\n  background: #fff7f7;\n  border-color: #fecaca;\n  color: #dc2626;\n}\n\n.ordenresumen-actions #btneliminarorden .material-symbols-outlined {\n  color: #ef4444;\n}\n\n.ordenresumen-actions #btnDespachar {\n  color: #0f766e;\n}\n\n.ordenresumen-actions #btnDespachar .material-symbols-outlined {\n  color: #0f766e;\n}\n\n.ordenresumen-chips {\n  display: flex;\n  flex-wrap: wrap;\n  gap: .8rem;\n  margin-bottom: 1rem;\n}\n\n.ordenresumen-chip {\n  border-radius: 999px;\n  display: inline-flex;\n  font-size: 1.35rem;\n  font-weight: 700;\n  line-height: 1;\n  padding: .85rem 1.2rem;\n}\n\n.ordenresumen-chip-muted {\n  background: #f1f5f9;\n  color: #334155;\n}\n\n.ordenresumen-chip-primary {\n  background: #eef2ff;\n  color: #4338ca;\n}\n\n.ordenresumen-chip-warning {\n  background: #fff7ed;\n  color: #c2410c;\n}\n\n.ordenresumen-emisor {\n  align-items: center;\n  border-bottom: 1px solid #dbe4f0;\n  color: #475569;\n  display: flex;\n  flex-wrap: wrap;\n  font-size: 1.45rem;\n  gap: .8rem;\n  margin-bottom: 1.6rem;\n  padding-bottom: 1.2rem;\n}\n\n.ordenresumen-emisor .btn-xs {\n  min-height: 3.2rem;\n  padding: .55rem 1rem;\n}\n\n.ordenresumen-metrics {\n  display: grid;\n  gap: 1rem;\n  grid-template-columns: repeat(4, minmax(0, 1fr));\n  margin-bottom: 1.8rem;\n}\n\n.ordenresumen-metric-card {\n  background: #fff;\n  border: 1px solid #dbe4f0;\n  border-radius: .8rem;\n  box-shadow: 0 8px 18px rgba(15, 23, 42, .04);\n  min-height: 9.2rem;\n  padding: 1.35rem;\n  text-align: left;\n}\n\n.ordenresumen-metric-card > p:last-child,\n.ordenresumen-metric-card button {\n  font-size: 1.5rem;\n  font-weight: 600;\n}\n\n.ordenresumen-metric-label {\n  align-items: center;\n  color: #526172;\n  display: flex;\n  font-size: 1.25rem;\n  font-weight: 700;\n  gap: .6rem;\n  margin: 0 0 .8rem;\n  text-transform: uppercase;\n}\n\n.ordenresumen-metric-label .material-symbols-outlined {\n  color: #4d46e5;\n  font-size: 2.2rem;\n}\n\n.ordenresumen-state {\n  color: #0f766e;\n  font-size: 1.55rem;\n  font-weight: 800;\n  margin: 0 0 .3rem;\n}\n\n.ordenresumen-main-grid {\n  display: grid;\n  gap: 1.6rem;\n  grid-template-columns: minmax(0, 1fr) 32rem;\n}\n\n.ordenresumen-products-card,\n.ordenresumen-info-card,\n.ordenresumen-bottom {\n  background: #fff;\n  border: 1px solid #dbe4f0;\n  border-radius: .8rem;\n  box-shadow: 0 8px 18px rgba(15, 23, 42, .04);\n}\n\n.ordenresumen-products-card {\n  min-height: 42rem;\n  overflow-x: auto;\n  padding: 1.3rem;\n}\n\n.ordenresumen-card-head {\n  align-items: center;\n  display: flex;\n  gap: 1rem;\n  justify-content: space-between;\n  margin-bottom: 1rem;\n}\n\