esumen-info-title {\n  font-size: 1.55rem;\n  margin-bottom: 1rem;\n}\n\n.ordenresumen-info-line {\n  align-items: center;\n  color: #475569;\n  display: flex;\n  font-size: 1.35rem;\n  gap: .55rem;\n  line-height: 1.35;\n  margin: .3rem 0;\n}\n\n.ordenresumen-bottom {\n  margin-top: 1.6rem;\n  padding: 1.4rem;\n}\n\n.ordenresumen-bottom-grid {\n  display: grid;\n  gap: 1.4rem;\n  grid-template-columns: minmax(0, 2fr) minmax(28rem, 1fr);\n}\n\n.ordenresumen-observations,\n.ordenresumen-payment-summary {\n  background: #f8fafc;\n  border: 1px solid #dbe4f0;\n  border-radius: .8rem;\n  padding: 1.35rem;\n}\n\n.ordenresumen-payment-summary p {\n  font-size: 1.35rem !important;\n}\n\n.ordenresumen-payment-summary #total {\n  font-size: 3.6rem !important;\n  white-space: nowrap;\n}\n\n#miDialogoEliminarOrden.orden-delete-dialog[open] {\n  display: flex;\n  flex-direction: column;\n  max-height: calc(100dvh - 2.4rem);\n  overflow: hidden;\n}\n\n#miDialogoEliminarOrden .orden-delete-dialog__header {\n  flex: 0 0 auto;\n}\n\n#miDialogoEliminarOrden .orden-delete-dialog__body {\n  flex: 1 1 auto;\n  min-height: 0;\n  padding-bottom: 0;\n}\n\n#miDialogoEliminarOrden .orden-delete-dialog__products {\n  max-height: clamp(16rem, 26dvh, 24rem);\n  overflow: auto;\n}\n\n#miDialogoEliminarOrden .orden-delete-dialog__products table {\n  min-width: 46rem;\n}\n\n#miDialogoEliminarOrden .orden-delete-dialog__footer {\n  box-shadow: 0 -12px 24px rgba(15, 23, 42, .08);\n  z-index: 2;\n}\n\n@media (max-width: 1100px) {\n  .ordenresumen-metrics,\n  .ordenresumen-main-grid,\n  .ordenresumen-bottom-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .ordenresumen-side {\n    display: grid;\n    grid-template-columns: repeat(3, minmax(0, 1fr));\n  }\n}\n\n@media (max-width: 768px) {\n  .ordenresumen-page {\n    padding: 1rem;\n  }\n\n  .ordenresumen-actions {\n    display: grid;\n    grid-template-columns: repeat(2, minmax(0, 1fr));\n  }\n\n  .ordenresumen-actions .btn-command {\n    max-width: