eight: 100vh;\r\n  height: 100%;\r\n  top: 0;\r\n  display: grid;\r\n  place-items: center;\r\n  background-color: rgba(0, 0, 0, 0.4);\r\n  overflow: hidden;\r\n}\r\n.spinner{\r\n  display: inline-block;\r\n  border: 4px solid rgba(0, 0, 0, 0.1);\r\n  width: 4rem;\r\n  height: 4rem;\r\n  border-radius: 50%;\r\n  border-left-color: v.$azul60;\r\n  animation: spinner 1s linear infinite;\r\n}\r\n\r\n\r\n\r\n.content-spinner1{\r\n  position: absolute;\r\n  //z-index: 3;\r\n  width: 100%;\r\n  //height: 100vh;\r\n  height: 100%;\r\n  top: 0;\r\n  display: grid;\r\n  place-items: center;\r\n  background-color: #eff2f79c;\r\n  overflow: hidden;\r\n}\r\n.spinner1{\r\n  display: inline-block;\r\n  border: 4px solid rgba(0, 0, 0, 0.1);\r\n  width: 4rem;\r\n  height: 4rem;\r\n  border-radius: 50%;\r\n  border-left-color: v.$azul60;\r\n  animation: spinner 1s linear infinite;\r\n  position: relative;\r\n  top: -30%;\r\n}\r\n\r\n@keyframes spinner{\r\n  0%{\r\n      transform: rotate(0deg);\r\n  }\r\n  100%{\r\n      transform: rotate(360deg);\r\n  }\r\n}",".pagination {\r\n  display: flex;\r\n  justify-content: center;\r\n  gap: 0.5rem;\r\n\r\n  li {\r\n    a {\r\n      display: inline-block;\r\n      padding: 0.5rem 1rem;\r\n      border: 1px solid #ddd;\r\n      border-radius: 0.25rem;\r\n      text-decoration: none;\r\n      color: #333;\r\n\r\n      &.disabled {\r\n        opacity: 0.4;\r\n        pointer-events: none;\r\n        cursor: default;\r\n      }\r\n\r\n      &:hover:not(.disabled) {\r\n        background-color: #f1f1f1;\r\n      }\r\n    }\r\n\r\n    &.active a {\r\n      background-color: #6366f1;\r\n      color: white;\r\n      border-color: #6366f1;\r\n    }\r\n  }\r\n}\r\n","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.content-dropdawn{\r\n    position: relative;\r\n}\r\n\r\n.btnmultiselect{\r\n    display: flex;\r\n    justify-content: space-between;\r\n    //height: 5rem;\r\n    align-items: center;\r\n    padding: 1rem 1.2rem;\r\n    border-radius: 1rem;\r\n    cursor: pointer;\r\n    background-color: v.$blanco;\r\n    max-width: 32rem;\r\n    //min-width: 26rem;\r\n    .btnmultiselect-text{\r\n        font-size: 1.5rem;\r\n        font-weight: 400;\r\n        color: v.$gris70;\r\n        margin-right: 1rem;\r\n    }\r\n    .arrow{\r\n        display: flex;\r\n        justify-content: center;\r\n        align-items: center;\r\n        height: 2.2rem;\r\n        width: 2.2rem;\r\n        background-color: v.$azul50;\r\n        border-radius: 50%;\r\n        color: v.$blanco;\r\n        transition: 0.3s;\r\n    }\r\n\r\n    &.open~ .list-items{\r\n            display: block;\r\n    }\r\n\r\n     &.open .arrow{\r\n        transform: rotate(-180deg);\r\n     } \r\n    \r\n}\r\n\r\n.list-items{\r\n    display: none;\r\n    min-width: 26.3rem;\r\n    max-width: 32rem;\r\n    position: absolute;\r\n    z-index: 15;\r\n    margin-top: 1.4rem;\r\n    background-color: v.$blanco;\r\n    border-radius: 1rem;\r\n    padding: 2rem 1.5rem 0rem 1.5rem;\r\n    .item{\r\n        height: 4rem;\r\n        color: v.$gris70;\r\n    }\r\n}\r\n","@use 'base/variables' as v;\r\n@use 'base/mixins' as m;\r\n\r\n.lineaencabezado {\r\n    font-family: v.$fuente-secundaria;\r\n    background-color: v.$azul100;\r\n    padding: 1.1rem 3rem;\r\n    color:v.$azul0;\r\n    text-align: center;\r\n    text-transform: uppercase;\r\n    font-weight: 400;\r\n    h1 {\r\n        font-size: 2.5rem;\r\n    }\r\n}\r\n.mensajetitulo {\r\n    @include m.desktop { \r\n        padding: 0 13rem;\r\n    }\r\n}\r\n.auth{\r\n    \r\n    /*max-width: 35rem;\r\n    width: 100%;\r\n    margin: 0 auto;*/\r\n    // padding: 2rem;\r\n    &__mensaje {\r\n        margin: 0 1.5rem;\r\n        @include m.desktop { \r\n            padding: 0 13rem;\r\n        }\r\n        p {\r\n            text-align: justify;\r\n            line-height: 1.4;\r\n        }\r\n    }\r\n    h2 {\r\n        margin: 1rem 1.5rem 2rem 1.5rem;\r\n    }\r\n    &__btnatras{\r\n     