  .sidebar-nav{\r\n            margin-top: 5rem;\r\n            a{              //el tamaño de las letras de los links a esta definido en globales.scss de 1.6rem\r\n                white-space: nowrap;\r\n                color: v.$gris30; //blanco\r\n                display: block;\r\n                margin-bottom: .8rem;\r\n                padding: 1rem;\r\n                transition-property: background-color;\r\n                transition-duration: 300ms;\r\n                font-size: 1.4rem;\r\n                text-align: center;\r\n                label{\r\n                    cursor: pointer;\r\n                }\r\n                &:hover, &.activo{\r\n                    //background-color: darken(v.$indigo, 20%);\r\n                    background-color: v.$azul0;\r\n                    border-radius: 0.5rem;\r\n                    /*border-bottom-left-radius: .5rem;\r\n                    border-top-left-radius: .5rem;\r\n                    background-color: v.$azul10;*/\r\n                    color: v.$indigo;\r\n                }\r\n                @include m.tablet{\r\n                    display: flex;\r\n                    align-items: center;\r\n                    gap: .5rem;\r\n                    font-size: 1.2rem;\r\n                    margin-bottom: .5rem;\r\n                    text-align: left;\r\n                }\r\n            }\r\n        }\r\n    \r\n    \r\n        .cerrar-sesion-mobile{  //clase al boton cerrar sesion que esta en el sidebar barra lateral\r\n            margin-top: 10rem;\r\n            @include m.tablet{\r\n               display: none;\r\n            }\r\n            p{\r\n                text-align: center;\r\n                margin: 0;\r\n                font-size: 1.4rem;\r\n                color: v.$cyan;\r\n                span{\r\n                    color: v.$blanco;\r\n                    font-weight: 700;\r\n                }\r\n            }\r\n            .cerrar-sesion{\r\n                @include m.boton